import { useState, useEffect, useRef } from "react";

const CONFIG = {
  readingSpeed: 6,
  minDelay: 2000,
  maxDelay: 12000,
  correctBase: 1500,
  wrongBase: 2500,
};
function getReadingSpeed(s) { return s >= 10 ? 10 : s >= 5 ? 8 : CONFIG.readingSpeed; }
function calcDelay(text, correct, streak) {
  const base = correct ? CONFIG.correctBase : CONFIG.wrongBase;
  const readTime = (text.length / getReadingSpeed(streak)) * 1000;
  return Math.min(Math.max(base, readTime), CONFIG.maxDelay);
}
const QUESTIONS = [
  { id: 1, field: "民法：債権", tag: "定期行為・無催告解除", q: "特定の日時にチケットが届かなければ契約の目的を達することができない性質の契約（定期行為）において、債務者が履行を遅滞した場合、債権者は催告をすることなく直ちに契約の解除をすることができる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！25日に届かなきゃ意味がないチケットは定期行為ちゃむ。遅れた時点で即解除できる権利が民法542条にあるんだちゃむ！", fb_ng: "不正解ちゃむ！時間を守れない債務者に催告してあげるような甘い条文は、民法には存在しないちゃむ！" },
  { id: 2, field: "民法：債権", tag: "債務不履行・帰責事由・損害賠償", q: "債務者が履行期に遅れた場合、その遅滞が個人的な事情によるものであっても、債務者の責めに帰すべき事由（過失など）がないと証明されない限り、債務者は損害賠償責任を免れない。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！準備不足は典型的な過失ちゃむ。過失がないことを証明できないなら責任は取るのが筋なんだちゃむ（民法415条）！", fb_ng: "不正解ちゃむ！準備不足は典型的な過失（責めに帰すべき事由）ちゃむ。言い訳の前に条文で武装するちゃむ！" },
  { id: 3, field: "民法：総則", tag: "意思能力・無効（3条の2）", q: "法律行為の当事者が、精神上の障害により、自己の行為の結果を判断するに足りる能力（意思能力）を一時的に欠いていた場合、その者が行った法律行為は無効となる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！意思能力がない状態での契約は最初からバグ（無効）ちゃむ（民法3条の2）。法が用意したセーフティネットに甘えていいんだちゃむ！", fb_ng: "不正解ちゃむ！取り消せるじゃなくて無効（最初からなかったこと）になるのがポイントちゃむ！" },
  { id: 4, field: "学習戦略", tag: "アウトプット先行学習", q: "初学者が既修者に追いつくためには、体系的な理解に時間をかけるよりも、早い段階から過去問に触れ、用語に慣れることが効率的である。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！完璧主義を捨てて過去問の海に飛び込むのが正解ちゃむ。不完全なまま回す勇気が、不可能を可能にするんだちゃむ！", fb_ng: "不正解ちゃむ！もっと勉強してからなんて言ってるのはただの足踏みちゃむ。即実戦投入するちゃむ！" },
  { id: 5, field: "生活法学", tag: "一石五鳥・合理的学習", q: "歩きながら音声で思考を整理し、耳で問題を聴くという複合習慣は、限られたリソースで最大の結果を生む合理的な戦略といえる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！時間が足りないからこそ生活のすべてを勉強に同期させるちゃむ。移動時間すら合格への燃料に変えるのが最強戦略なんだちゃむ！", fb_ng: "不正解ちゃむ！机に向かうだけが勉強じゃないちゃむ。生活を丸ごと学習に変換するのが一石五鳥の極意なんだちゃむ！" },
  { id: 6, field: "民法：債権", tag: "委任・善管注意義務（644条）", q: "受任者は、委任の本旨に従い、善良な管理者の注意をもって事務を処理する義務を負うが、報酬を受けない無償の委任であれば、この注意義務は軽減される。", a: "×", choices: ["○", "×"], fb_ok: "正解ちゃむ！無償でもガッツリ善管注意義務は課されるちゃむ（民法644条）！タダだからといって手を抜けないのが法の厳しさだちゃむ！", fb_ng: "不正解ちゃむ！タダだからうっかりしてもOKなんて理屈は通らないちゃむ。プロとして引き受けた以上責任は重いんだちゃむ！" },
  { id: 7, field: "民法：債権", tag: "事務管理・費用償還（702条）", q: "義務なく他人のために清掃や害虫駆除等を行った場合でも、その管理が本人の利益に適合するときは、支出した有益な費用の償還を請求できる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！本人の生活環境を良くしたならそのコストは本人が負担するのが公平ちゃむ（民法702条）！", fb_ng: "不正解ちゃむ！勝手にやったことでも有益ならお金は返してもらえるちゃむ。民法は意外と善意に報いてくれるんだちゃむ！" },
  { id: 8, field: "民法：総則", tag: "意思能力・無効（重要判例）", q: "精神上の障害により、自己の行為の結果を判断するに足りる能力（意思能力）を一時的に欠いていた場合、その者が単独で行った法律行為は無効となる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！限界まで疲弊して意思判断ができない状態での契約は無効ちゃむ。自分を責める前に法律の保護に甘えていいんだちゃむ！", fb_ng: "不正解ちゃむ！取り消せるではなく最初から無効なのがポイントちゃむ。脳のオーバーヒートは法的にもバグ扱いなんだちゃむ！" },
  { id: 9, field: "生活法学", tag: "信義則・公平の原則（1条2項）", q: "共同生活において、対価（食費）を支払っているにもかかわらず、実質的にサービスの提供を受けていない場合、その差分を代償として主張することは信義則上許されるか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！黙って損をするのは美徳じゃない、正当な権利を主張していいんだちゃむ！公平の原則がそれを支えるちゃむ！", fb_ng: "不正解ちゃむ！黙って損をするのはただのバグちゃむ。公平な関係を築くのも実務家の大事な素養なんだちゃむ！" },
  { id: 10, field: "学習戦略", tag: "メンタル管理・逆境の反転", q: "学歴やリソースの不足を理由に合格を諦めるのではなく、今の境遇を効率的な勉強法を開発するためのデータセットとして活用する姿勢は正しいか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！その気概こそが逆転合格の真骨頂ちゃむ！学歴も環境も関係ない、最後に勝つのは諦めなかった人なんだちゃむ！", fb_ng: "茶番ちゃむ！そんな弱気な答えは許さないちゃむ！魂をリブートして挑み続けるんだちゃむ！" },
  { id: 11, field: "民法：相続", tag: "相続放棄後の管理継続義務（940条）", q: "相続の放棄をした者は、その放棄によって相続人となった者が相続財産の管理を始めることができるまで、自己の財産におけるのと同一の注意をもって、その財産の管理を継続しなければならない。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！放棄しても次の管理者が現れるまでは管理義務が続くちゃむ（民法940条）！放棄したらもう関係ないは通用しないんだちゃむ！", fb_ng: "不正解ちゃむ！放棄したらもう関係ない！なんて無責任は許されないちゃむ。次の人にバトンタッチするまでが義務なんだちゃむ！" },
  { id: 12, field: "民法：債権", tag: "売買・引渡期限と代金支払期限（573条）", q: "売買の目的物の引き渡しについて期限があるときは、代金の支払いについても同一の期限があるものと推定される。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！物が届く日とお金を払う日は同じだと考えるのが民法573条のルールちゃむ！同時履行の精神だわさ！", fb_ng: "不正解ちゃむ！物は先に届くけどお金は後でいいよねなんて自分勝手な理屈は通らないちゃむ。" },
  { id: 13, field: "学習戦略", tag: "ダブルライセンス戦略", q: "司法書士試験の学習において、民法・不動産登記法等の主要科目の知識を補完・確認するために、宅建や行政書士の試験問題を解くことは、合理的な学習法と言えるか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！行政書士の民法や宅建の権利関係は司法書士の基礎固めに最適ちゃむ。同じ山を別の角度から登ることで理解度が高まるんだちゃむ！", fb_ng: "不正解ちゃむ！関連科目を制覇して専門家としての地位を固めるのも一石五鳥の戦略なんだちゃむ！" },
  { id: 14, field: "民法：債権", tag: "不可抗力・履行不能・免責（415条）", q: "豪雪等の自然災害により、債務者が物理的に履行を継続することが不可能となった場合、その不履行が債務者の責めに帰すべき事由によらないものであるときは、債務者は損害賠償責任を負わない。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！不可抗力による履行不能は免責されるちゃむ（民法415条1項但書）！まずは体を休めるのが先決なんだちゃむ！", fb_ng: "不正解ちゃむ！人間、3メートルの雪には勝てないちゃむ。不可抗力に対して責任を問うのは民法の信義則に反するんだちゃむ！" },
  { id: 15, field: "学習戦略", tag: "長期計画・合理的意思決定", q: "合格目標を延期し、現在の極限環境に合わせて学習計画を再構築することは、長期的な合格率を高めるための合理的な意思決定と言えるか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！短期決戦で自滅するより着実に地層を固めるのが真のプロだわさ！勇気ある撤退こそが勝利へのラストピースなんだちゃむ！", fb_ng: "不正解ちゃむ！固執して倒れるのは合格から一番遠ざかる行為ちゃむ。戦略的撤退の勇気が必要なんだちゃむ！" },
  { id: 16, field: "民法：債権", tag: "緊急事務管理・注意義務の軽減（698条）", q: "他人の身体、自由または名誉に対する急迫の危害を免れさせるために事務管理をした者は、悪意または重大な過失がなければ、これによって生じた損害について賠償責任を負わない。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！切迫した状況での善意の行動は軽過失なら許されるのが698条の慈悲ちゃむ！", fb_ng: "不正解ちゃむ！切迫した状況で完璧を求めるのは酷ちゃむ。必死で動いた善意の人を法律はちゃんと守ってくれるんだちゃむ！" },
  { id: 17, field: "民法：債権", tag: "安全配慮義務・労働契約", q: "使用者は、労働契約に伴い、労働者がその生命、身体等の安全を確保しつつ労働することができるよう、必要な配慮をする義務（安全配慮義務）を負い、これに違反して損害を与えた場合、債務不履行に基づく損害賠償責任を負う。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！安全に働かせるのはオプションじゃなく絶対の義務なんだちゃむ！職場の怠慢は許してはいけないんだちゃむ！", fb_ng: "不正解ちゃむ！仕事なんだから我慢しろというのはブラック企業の茶番ちゃむ。労働者の命を守るのが法の最優先事項なんだちゃむ！" },
  { id: 18, field: "民法：総則", tag: "公序良俗・権利の濫用（90条・1条3項）", q: "形式的には権利の行使であっても、社会通念上許容される範囲を超える過酷な労働の強制は、権利の濫用として認められない場合がある。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！指揮命令権だって万能じゃないちゃむ！度を越したムチャ振りは法的にバグとして無効化できるんだちゃむ！", fb_ng: "不正解ちゃむ！命令絶対の劇は民法にはないちゃむ。権利の濫用として弾き返せるんだちゃむ！" },
  { id: 19, field: "学習戦略", tag: "実務家の視点・証拠確保", q: "将来の司法書士として、自らの不当な労働環境に対し、事実関係を記録し、法的な根拠に基づいて改善を求める姿勢は、実務家としての素養を磨く訓練と言えるか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！自分の権利すら守れない者に他人の権利は守れないちゃむ。今の状況を記録することは最強の実務演習なんだちゃむ！", fb_ng: "茶番ちゃむ！泣き寝入りは司法書士の辞書にはないちゃむ。怒りを条文という弾丸に変えて戦い抜くんだちゃむ！" },
  { id: 20, field: "民法：債権", tag: "安全配慮義務・附随的義務", q: "雇用契約またはそれに準ずる契約において、使用者は労働者に対し、単に報酬を支払うだけでなく、労働者の生命・身体等の安全を確保しつつ労働できるよう必要な配慮をする義務（附随的義務）を負う。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！安全に働かせるのはオプションじゃなく絶対の義務なんだちゃむ！給料払ってるんだから文句言うなは通らないちゃむ！", fb_ng: "不正解ちゃむ！労働者の心身を削るような環境放置は明確な債務不履行ちゃむ。全員を安全に働かせるまでが会社の仕事なんだちゃむ！" },
  { id: 21, field: "民法：総則", tag: "信義則・情報提供義務（1条2項）", q: "契約関係にある当事者間において、一方が他方の不利益を回避するために必要な重要情報を意図的に隠蔽し、その結果他方に著しい過度な負担が生じた場合、その隠蔽行為は信義則（1条2項）に反するものとして不法行為責任を構成し得るか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！信義則はブラックな隠蔽を許さないんだちゃむ！共同関係における誠実さを信義則は要求するちゃむ！", fb_ng: "不正解ちゃむ！プライバシーだから何を隠してもいいなんてのは茶番ちゃむ。役割分担に直結する情報は適切に共有されるべきだちゃむ！" },
  { id: 22, field: "民法：債権", tag: "安全配慮義務・人員配置", q: "使用者は、特定の労働者の心身の状態を把握しながら、他の労働者に対してその補填のための過重な労働を強いる際、当該労働者の健康を損なわないよう配慮する義務を負う。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！そのしわ寄せを特定の一人に無策で押し付けるのは安全配慮義務違反のダブルパンチちゃむ！全員を守るのが法の平等なんだちゃむ！", fb_ng: "不正解ちゃむ！あっちが障害者だからしょうがないで済ませてはいけないちゃむ。全員の体と心を同じ重さで守るのが法の平等なんだちゃむ！" },
  { id: 23, field: "学習戦略", tag: "権利意識・法的思考", q: "自身に生じている不利な状況の原因を、人間関係の問題として片付けるのではなく、契約上の義務違反や法の原則に照らして客観的に分析する姿勢は、事案分析力の向上に寄与するか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！感情を法理に昇華させること。これができるようになったら、もう半分司法書士になったようなものちゃむ！", fb_ng: "茶番ちゃむ！運が悪かったで終わらせるのは受験生じゃないちゃむ。すべての不利益を条文で裁いて自分の地層の肥やしにするのが正解だちゃむ！" },
  { id: 24, field: "民法：債権", tag: "不法行為・人格権・精神的平穏（709条）", q: "特定の同僚に対し、LINEを通じて執拗に誹謗中傷や嫌がらせのメッセージを送信する行為は、たとえ1対1の通信であっても、受信者の精神的平穏を害するものとして、人格権の侵害に基づく不法行為（709条）を構成し得る。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！LINEは便利な道具だけど刃物と同じちゃむ。相手の心を切り刻むようなメッセージは立派な権利侵害として損害賠償の対象になるんだちゃむ！", fb_ng: "不正解ちゃむ！嫌なら見なきゃいいなんて劇は通らないちゃむ。一方的に送りつけられる悪意は法の盾で防ぐべき侵害行為なんだちゃむ！" },
  { id: 25, field: "民法：債権", tag: "安全配慮義務・職場環境維持義務", q: "会社が、一部の従業員による他の従業員への嫌がらせ行為を把握した場合、職場環境を適正に維持する義務（安全配慮義務の派生）に基づき、被害拡大を防ぐための適切な措置を講じる義務を負う。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！会社が義務を果たそうとした当然の措置だちゃむ！社員が安心して働ける環境を整えるまでが会社の仕事なんだちゃむ！", fb_ng: "不正解ちゃむ！会社が嫌がらせを放置するのは債務不履行（義務違反）ちゃむ。放置は立派な法律違反なんだちゃむ！" },
  { id: 26, field: "学習戦略", tag: "動機・法的救済・職業倫理", q: "自身が受けた不当な扱いを機に、法的な知識による解決と救済を目指して司法書士を志すことは、職業倫理における誠実義務の基礎となる強い動機となり得るか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！痛みを知る者は他人の痛みにも敏感になれるちゃむ。その怒りを合格証書を掴み取るための正義の炎に変えるんだちゃむ！", fb_ng: "茶番ちゃむ！きれいごとだけで司法書士は務まらないちゃむ。現場の地獄を知る者こそが真に頼れる実務家になるんだちゃむ！" },
  { id: 27, field: "民法：総則", tag: "信義則・権利の濫用・最後の切り札（1条）", q: "民法第1条に規定される基本原則（信義則、権利濫用の禁止）は、具体的な条文がない事案においても、裁判所が妥当な解決を導き出すための切り札として機能する。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！1条の正義の鉄槌があるからこそブラックな環境も裁けるんだちゃむ！法律に書いてないからって泣き寝入りしなくていいちゃむ！", fb_ng: "不正解ちゃむ！1条はただの飾りじゃないちゃむ。すべての条文を貫く民法の魂なんだちゃむ！" },
  { id: 28, field: "民法：債権", tag: "不法行為・慰謝料・精神的損害（710条）", q: "不法行為に基づく損害賠償において、財産的な損害（治療費等）だけでなく、精神的な苦痛に対する慰謝料も損害の範囲に含まれる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！目に見えない傷も民法は見逃さないんだちゃむ（民法710条）！精神的な苦痛も立派な損害として賠償請求できるちゃむ！", fb_ng: "不正解ちゃむ！心が痛いだけならタダなんて冷たい劇は民法にはないちゃむ。710条が涙を賠償金という名の正義に変えてくれるんだちゃむ！" },
  { id: 29, field: "民法：総則", tag: "人格権・差止請求権", q: "人格権（生命、身体、名誉、プライバシー等）が不当に侵害されている場合、被害者は加害者に対して、損害賠償だけでなく、将来の侵害を止めるよう求める権利（差止請求権）を有する。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！侵害を未然に防ぎ今ある平穏を取り戻すのも実務家の重要な仕事なんだちゃむ！やられっぱなしは茶番ちゃむ！", fb_ng: "不正解ちゃむ！やられっぱなしで賠償金を待つだけなんて茶番ちゃむ。差止請求で侵害を今すぐ止める権利があるんだちゃむ！" },
  { id: 30, field: "民法：相続", tag: "死亡と相続開始（882条）", q: "人が死亡したときは、その死亡の時から相続が開始する。また、戸籍法の規定により死亡の報告がなされた場合（認定死亡）も、法律上の死亡と同一の効果が生じる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！民法882条では死亡が相続の絶対的なトリガーなんだちゃむ。心臓が止まったその瞬間に権利義務のバトンタッチは始まっているんだちゃむ！", fb_ng: "不正解ちゃむ！葬儀が終わってから相続なんて悠長な劇は民法にはないちゃむ！" },
  { id: 31, field: "民法：債権", tag: "委任と代理の区別", q: "受任者は、委任事務を処理するにあたって必要があるときは、本人に代わって第三者と法律行為を行う代理権を当然に有する。", a: "×", choices: ["○", "×"], fb_ok: "正解ちゃむ！代理と委任は別物ちゃむ！事務を頼まれたからといって勝手にハンコを押せる代理権までセットで付いてくるわけじゃないちゃむ。", fb_ng: "不正解ちゃむ！何でもやっていいなんて白紙委任の茶番は危険すぎるちゃむ！代理権が授与されているかどうか厳密にチェックするのがプロの眼なんだちゃむ！" },
  { id: 32, field: "民法：債権", tag: "期限の利益の喪失（137条）", q: "代金後払いの特約がある売買契約において、代金の支払期限が到来する前に、買主が破産手続開始の決定を受けた場合、買主は期限の利益を喪失し、売主は直ちに代金の支払を請求することができる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！1ヶ月後の支払いでいいという期限の利益は、買主がパンク（破産）したら消滅しちゃうちゃむ（民法137条）！", fb_ng: "不正解ちゃむ！まだ1ヶ月経ってないから払わないは、破産した瞬間に通用しなくなるちゃむ。137条の期限の利益喪失事由を脳に刻むんだちゃむ！" },
  { id: 33, field: "民法：債権", tag: "書面によらない贈与・履行完了（550条）", q: "書面によらない贈与契約は、各当事者がいつでも解除することができるが、既に履行が終わった部分については、もはや解除することができない。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！一度受け取ったら後から返してとは言えないのが法の鉄則だちゃむ（民法550条）！", fb_ng: "不正解ちゃむ！書面がなくても物が届いて受け取っちゃえば契約はガッチリ固定されるちゃむ。受領後の解除はNGなんだちゃむ！" },
  { id: 34, field: "民法：債権", tag: "特定物債権・善管注意義務（400条）", q: "特定物の引渡しを目的とする債権の債務者は、その引渡しをするまで、自己の財産に対するのと同一の注意をもって、その物を保存しなければならない。", a: "×", choices: ["○", "×"], fb_ok: "正解ちゃむ！自己の財産と同一じゃ甘いちゃむ！400条では善良な管理者の注意（善管注意義務）が求められるちゃむ。一段上の義務が必要なんだちゃむ！", fb_ng: "不正解ちゃむ！自分の物と同じくらい適当に扱うのは茶番ちゃむ。特定物を渡す義務があるなら善管注意義務を果たすのが常識だわさ！" },
  { id: 35, field: "民法：債権", tag: "不法行為・故意過失・709条", q: "不法行為に基づく損害賠償において、加害者が故意または過失によって他人の権利を侵害した場合、被害者はその損害の賠償を請求することができる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！民法709条の基本ちゃむ。故意でも過失でも、権利を侵害して損害を与えたら賠償義務が発生するんだちゃむ！", fb_ng: "不正解ちゃむ！故意だけでなくうっかり（過失）でも損害を与えたら賠償義務が生じるのが709条の鉄則ちゃむ！" },
  { id: 36, field: "民法：総則", tag: "信義則の機能・附随的義務", q: "信義誠実の原則（1条2項）は、当事者が具体的な合意をしていない事項についても、契約関係から生じる附随的義務（安全配慮義務・情報提供義務等）の根拠となり得る。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！信義則は条文に書いてない義務を生み出す強力な原則ちゃむ！安全配慮義務も情報提供義務もここから生まれるんだちゃむ！", fb_ng: "不正解ちゃむ！1条2項は飾りじゃないちゃむ。当事者が予想していなかった義務も信義則が補充してくれる強力なツールなんだちゃむ！" },
  { id: 37, field: "民法：債権", tag: "使用者責任（715条）", q: "被用者が事業の執行について第三者に損害を加えた場合、使用者は、その選任及び事務の監督について相当の注意をしたことを証明しなければ、損害賠償責任を負う。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！使用者責任（民法715条）ちゃむ！部下が起こしたトラブルは会社も責任を取らなきゃいけないんだちゃむ！", fb_ng: "不正解ちゃむ！部下がやったことだから俺は知らないは通らないちゃむ。監督を怠った使用者にも責任が及ぶのが715条の鉄槌だちゃむ！" },
  { id: 38, field: "民法：総則", tag: "法の下の平等・公平の原則", q: "民法における公平の原則とは、当事者間の利益の均衡を図ることであり、一方が不当に利益を得て他方が損失を被る事態を防ぐための理念として機能する。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！不当利得や損害賠償の根底にある公平の原則ちゃむ。一方だけが得して一方だけが損するのを民法は許さないんだちゃむ！", fb_ng: "不正解ちゃむ！公平の原則は民法全体を貫く重要理念ちゃむ。不当利得・損害賠償・信義則すべての根っこにあるんだちゃむ！" },
  { id: 39, field: "生活法学", tag: "法的思考・日常への応用", q: "日常生活で生じる様々な出来事（労働・取引・家族関係等）を民法の条文や判例に照らして分析する習慣は、法的思考力を養うための最も実践的な学習方法の一つといえる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！日常の出来事を条文に紐づける習慣こそが試験問題を瞬時に解く直感を育てるちゃむ！生活が全部テキストになるんだちゃむ！", fb_ng: "不正解ちゃむ！机の上だけが勉強の場じゃないちゃむ。生活の中で法律を感じ取れるようになったら合格は半分手に入ったようなものだちゃむ！" },
  { id: 40, field: "民法：債権", tag: "同時履行の抗弁権（533条）", q: "売買契約において、売主が代金を受け取るまで目的物を引き渡さないと主張し、買主が目的物の引渡しを受けるまで代金を支払わないと主張することは、互いに同時履行の抗弁権として認められる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！同時履行の抗弁権（民法533条）ちゃむ！先に払った方が損をするリスクを防ぐための取引の基本ルールなんだちゃむ！", fb_ng: "不正解ちゃむ！お互いが相手の履行を条件に自分も履行するのが同時履行ちゃむ。これを主張することで遅滞責任も免れるんだちゃむ！" },
  { id: 41, field: "民法：総則", tag: "制限行為能力者・取消（5条）", q: "未成年者が法定代理人の同意を得ずに行った法律行為は、取り消すことができる。ただし、単に権利を得、または義務を免れる行為については、この限りでない。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！未成年者の保護ルール（民法5条）ちゃむ！ただしもらうだけ・借金が消えるだけの行為は同意なしでOKなんだちゃむ！", fb_ng: "不正解ちゃむ！未成年者の行為は原則取消可能ちゃむ。ただし権利だけ得る行為（プレゼントをもらう等）は同意不要なんだちゃむ！" },
  { id: 42, field: "民法：債権", tag: "連帯保証・補充性なし（454条）", q: "連帯保証人は、債権者から請求を受けた場合であっても、まず主たる債務者に請求するよう求める権利（催告の抗弁権）を有しない。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！連帯保証には補充性がないちゃむ（民法454条）！まず主債務者にと言えないのが連帯保証の怖いところなんだちゃむ！", fb_ng: "不正解ちゃむ！連帯保証人は催告の抗弁権も検索の抗弁権も持たないちゃむ。主債務者と同じように直接請求される立場なんだちゃむ！" },
  { id: 43, field: "民法：物権", tag: "占有と本権の区別", q: "占有権は、物を事実上支配する状態を保護するものであり、本権（所有権等）の存在とは独立して成立する。そのため、泥棒にも占有権は生じる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！占有は事実状態の保護ちゃむ。本権がなくても占有は成立するし、占有訴権で守られるんだちゃむ！", fb_ng: "不正解ちゃむ！泥棒でも占有権は成立するちゃむ。占有は事実の支配状態を保護するものであり正当な権利の有無は関係ないんだちゃむ！" },
  { id: 44, field: "民法：総則", tag: "錯誤・取消（95条）", q: "法律行為の基礎とした事情についての認識が真実に反する錯誤（動機の錯誤）も、その事情が法律行為の基礎とされていることが表示されていたときは、取り消すことができる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！R2改正で動機の錯誤も取消の対象になったちゃむ（民法95条2項）！動機が相手方に示されていることが条件だわさ！", fb_ng: "不正解ちゃむ！改正民法では動機の錯誤も取消できるようになったちゃむ。動機を相手に示していた場合に限られるのがポイントなんだちゃむ！" },
  { id: 45, field: "民法：債権", tag: "受領遅滞（413条）", q: "債権者が弁済の提供を受けることを拒否した場合、債務者は受領遅滞を主張することができ、その後の履行不能について帰責事由がないものとして扱われる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！受領遅滞（民法413条）ちゃむ！受け取ってくれない債権者のせいで物が滅失しても債務者は責任を免れるんだちゃむ！", fb_ng: "不正解ちゃむ！ちゃんと提供したのに受け取ってくれない債権者のせいで損害が生じても债务者が責任を取る必要はないちゃむ。受領遅滞の効果を覚えるちゃむ！" },
  { id: 46, field: "民法：債権", tag: "不当利得の返還（703・704条）", q: "善意の受益者は現に利益を受けている限度においてのみ返還義務を負うが、悪意の受益者は受けた利益に利息を付して返還し、なお損害があるときはその賠償の責任を負う。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！善意なら現存利益だけ、悪意なら全額＋利息＋損害賠償ちゃむ（民法703条・704条）。善悪で大きく結果が変わるちゃむ！", fb_ng: "不正解ちゃむ！善意受益者は現存利益だけ返せばOK。悪意受益者は利息まで付けてフル返還ちゃむ。善悪の区別をしっかり覚えるちゃむ！" },
  { id: 47, field: "生活法学", tag: "民法は生活のルールブック", q: "民法は、抽象的な法律論だけでなく、日常生活における取引・労働・家族・財産管理のあらゆる場面に適用される実用的なルールブックである。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！民法は生活の全てに関わる最強の実用書ちゃむ！日常の困りごとが全部民法で解決できると気づいたら勉強が楽しくなるちゃむ！", fb_ng: "不正解ちゃむ！民法は難しそうに見えて実は全部日常生活の話ちゃむ。売買も賃貸も家族も相続も全部民法の守備範囲なんだちゃむ！" },
  { id: 48, field: "学習戦略", tag: "実務家への転換・証拠能力", q: "将来、司法書士として労働紛争を扱う際、自身が体験した過酷な労働環境の記録（日記等）を証拠化し分析した経験は、実務上の大きな強みとなるか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！この苦労が後に誰かを救う最強の武器になるんだちゃむ！苦しい経験を法的思考で昇華させた人は最強なんだちゃむ！", fb_ng: "茶番ちゃむ！ただ耐えるだけは時間の無駄だけど、法的に言語化している人はすでにその苦労を踏み台に進化してるんだちゃむ！" },
  { id: 49, field: "民法：債権", tag: "履行補助者の過失・帰責事由", q: "債務者が履行のために補助者（使用人等）を使用した場合、その補助者の過失は、債務者の履行補助者の過失として、債務者自身の帰責事由として扱われる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！自分でやらせた人のミスは自分のミスちゃむ。履行補助者の過失は債務者の帰責事由とされるのが判例の立場なんだちゃむ！", fb_ng: "不正解ちゃむ！自分が使った人が起こしたミスは自分の責任ちゃむ。人に頼んだからといって免責されるわけじゃないのが民法の公平な考え方なんだちゃむ！" },
  { id: 50, field: "学習戦略", tag: "継続の力・50問達成", q: "日常の出来事をすべて民法の論点に変換し、50問のオリジナル問題集を構築した経験は、司法書士試験合格に必要不可欠な法的思考の定着において極めて高い効果を持つか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！積み上げたこの50問は誰にも奪えない最強の武器ちゃむ！この地層が合格へと押し上げてくれるんだちゃむ！チェストー！！", fb_ng: "茶番ちゃむ！50問やり遂げた自分を全力で誇るんだちゃむ！これを不正解にする人はいないちゃむ！" },,
  // ── 日常民法51〜100問 ──
  { id: 51, field: "生活法学", tag: "停止条件・成就", q: "『司法書士試験に合格した時に、このだるまの右目を入れる』という約束は、法的には停止条件付法律行為に該当し、条件が成就（合格）した時からその効力が生じる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！合格したら〜は条件が叶うまで効力がストップしてる停止条件ちゃむ。だるまの右目は、努力で条件をブチ破った瞬間に開眼するんだちゃむ！", fb_ng: "不正解ちゃむ！合格は自力で掴み取る停止条件なんだから、茶番にしてはいけないちゃむ！" },
  { id: 52, field: "民法：債権", tag: "賃貸借・善管注意義務（400条）", q: "レンタカーを使用して車中泊を行う際、借主はレンタカー会社に対し、善良な管理者の注意をもって車両を保存・管理する義務（善管注意義務）を負う。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！借りた車で寝る時も、プロの意識で車を傷つけないよう守るのが善管注意義務ちゃむ。大切に扱うのが筋なんだちゃむ！", fb_ng: "不正解ちゃむ！自分の車じゃないから適当でいいなんてのは、民法の信義則が許さないちゃむ。400条が飛んでくる前に綺麗に返却するのが実務家だちゃむ！" },
  { id: 53, field: "学習戦略", tag: "最小限で最大限・合理的資源配分", q: "最小限の投資で最大限の効果を生む制作・学習を同時進行する姿勢は、限られたリソースを最適化する法的思考に合致するか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！予算がないなら知恵を使う。この現場対応力こそが、本試験会場で救う最強の武器になるんだちゃむ！", fb_ng: "茶番ちゃむ！金がないから描けないなんて言い訳は、辞書にはないはずちゃむ！不退転の決意を叩き込むんだちゃむ！" },
  { id: 54, field: "民法：債権", tag: "賃貸借・必要費の直ちに請求（608条1項）", q: "レンタカーの使用中にタイヤがパンクし、借主が自費で修理した場合、借主はレンタカー会社に対し、その修理代（必要費）の償還を直ちに請求することができる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！民法608条1項により、借りた物の維持に必要な費用を出したときは、即座に返せと言える権利があるちゃむ！", fb_ng: "不正解ちゃむ！返却時まで待てなんて劇は通用しないちゃむ。必要費は直ちに請求できるのが、有益費との大きな違いなんだちゃむ！" },
  { id: 55, field: "民法：債権", tag: "運行供用者責任・自賠法", q: "息子が運転するレンタカーに同乗していた者が、息子の過失による事故で負傷した場合、レンタカー会社（運行供用者）に対しても、自賠法に基づく損害賠償を請求できる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！運転しているのが息子さんでも、車の支配権を持つレンタカー会社は運行供用者として責任を負うのが原則ちゃむ！", fb_ng: "不正解ちゃむ！身内の運転だから会社は関係ないという理屈は通らないちゃむ。被害者を広く守るための強力な盾があるんだちゃむ！" },
  { id: 56, field: "民法：債権", tag: "無断転貸・解除（612条2項）", q: "レンタカーの契約者が、会社の承諾を得ることなく、第三者にその車両を運転（転貸）させた場合、レンタカー会社は催告をすることなく直ちに契約を解除することができる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！民法612条2項の無断転貸による解除ちゃむ！勝手に他人に使わせるのは最大の裏切り（背信行為）なんだちゃむ！", fb_ng: "不正解ちゃむ！ちょっと貸しただけは通用しないちゃむ。無断でまた貸しをしたら即座にアウト！というのが民法の厳しさだちゃむ！" },
  { id: 57, field: "民法：物権", tag: "自力救済の禁止・占有権", q: "駐車場の利用時間を大幅に過ぎて無断で車中泊を続けている車両に対し、駐車場の管理者は、裁判手続を経ることなく、自らレッカー移動等の実力行使によって排除することができる。", a: "×", choices: ["○", "×"], fb_ok: "正解ちゃむ！日本法では自力救済は原則禁止ちゃむ。たとえ不法占拠でも、無理やりどかすには裁判所の力を借りなきゃいけないんだちゃむ！", fb_ng: "不正解ちゃむ！力づくで解決するのは茶番ちゃむ。法治国家では、たとえ正義でも手続きを飛ばすことは許されないんだちゃむ！" },
  { id: 58, field: "民法：債権", tag: "不当利得・駐車場代（703条）", q: "無断で駐車場の区画を使用し車中泊を行った者は、法律上の原因なく他人の財産によって利益を受け、反面に他人に損失を与えたとして、その利用相当額を不当利得として返還する義務を負う。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！民法703条ちゃむ！タダで寝られてラッキーは通らないちゃむ。本来払うべき駐車代という利益を返せと言われるのが不当利得の理屈なんだちゃむ！", fb_ng: "不正解ちゃむ！得をした分は返す、これが民法の公平の原則ちゃむ。知らない間に発生している債務に気づくのがプロの受験生だちゃむ！" },
  { id: 59, field: "民法：債権", tag: "工作物責任・無過失責任（717条）", q: "駐車場の設備の欠陥（照明の故障や段差の放置）が原因で、車中泊中の利用者が負傷した場合、駐車場の所有者は、損害の発生を防止するのに必要な注意を払っていたとしても、無過失責任を負う場合がある。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！民法717条の土地の工作物責任ちゃむ！所有者は、過失がなくても責任を負わされる無過失責任という重い十字架を背負っているんだちゃむ！", fb_ng: "不正解ちゃむ！注意してたから悪くないが通用しないのが工作物責任の怖いところちゃむ。被害者を守るための厳しい鉄槌なんだちゃむ！" },
  { id: 60, field: "民法：債権", tag: "和解・確定効（696条）", q: "当事者が互いに譲歩して争いをやめることを約する和解契約が成立した場合、その内容が真実の権利関係と異なっていたとしても、当事者はもはや和解の内容に反する主張をすることができない。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！民法696条の確定効ちゃむ！水面下で手を打とうと決めたら、後から蒸し返すことはできないのが法の安定なんだちゃむ！", fb_ng: "不正解ちゃむ！後から証拠が見つかったから無効だ！なんて劇は和解の前では通用しないちゃむ。一度決めたら終わらせるのが紛争解決の鉄則だちゃむ！" },
  { id: 61, field: "民法：総則", tag: "消滅時効・5年（166条）", q: "権利を行使することができることを知った時から5年間行使しないときは、その債権は時効によって消滅する。これは『権利の上に眠る者は保護しない』という法の趣旨に基づくものである。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！モタモタしているうちに、法的に戦う権利が消えてしまうこともあるちゃむ！訴えるならタイミングを逃さないのがプロの眼なんだちゃむ！", fb_ng: "不正解ちゃむ！いつまでも怒っていれば権利は残るなんてのは茶番ちゃむ。法は時間の経過とともに争いを強制的に終わらせるシステムを持っているんだちゃむ！" },
  { id: 62, field: "学習戦略", tag: "ADR・実務家のバランス感覚", q: "司法書士は、裁判（訴訟）だけでなく、当事者間の交渉やADR（裁判外紛争解決手続）を通じて、水面下での円満な解決を図ることも重要な役割の一つである。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！水面下の9割を、いかに公平に最小限のコストでさばくか。これこそが世界一コスパの良い実務家への道なんだちゃむ！", fb_ng: "茶番ちゃむ！何でも裁判だ！と叫ぶのは依頼人の財布を削るだけの素人ちゃむ。水面下をコントロールできてこそ真の権利の守護神なんだちゃむ！" },
  { id: 63, field: "民法：債権", tag: "安全配慮義務・過酷な労働環境", q: "使用者が、防寒設備が不十分な環境（室温6度等）や、過度な肉体労働（大量の手作業除雪等）を恒常的に強いることで労働者の健康を害した場合、労働者は安全配慮義務違反に基づき、損害賠償を請求することができる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！室温6度は生存の危機ちゃむ！会社は社員を凍えさせてはいけない義務があるちゃむ。この寒さは立派な証拠になるんだちゃむ！", fb_ng: "不正解ちゃむ！北国だから当たり前なんて劇は通らないちゃむ。法は、どんな猛吹雪の中でも労働者の最低限の健康を守るためにあるんだちゃむ！" },
  { id: 64, field: "民法：債権", tag: "事務管理・費用償還（697条・702条）", q: "おばあちゃん達の食料品を購入して届ける行為は、法的な義務がない場合であっても、他人のために事務を管理する『事務管理』に該当し、管理者は本人に対して支出した費用（代金）を請求できる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！民法697条の事務管理ちゃむ！善意の買い出しも法的には善意の管理として認められ、かかったお金はキッチリ返せと言えるんだちゃむ！", fb_ng: "不正解ちゃむ！勝手にやったんだから自腹だろなんてのは冷たい茶番ちゃむ。その苦労は法的に清算されるべき権利なんだちゃむ！" },
  { id: 65, field: "学習戦略", tag: "カレンダー備忘録・タイムマネジメント", q: "膨大な知識を扱う学習において、手帳に詳しく書く時間を削り、パッと見て瞬時に把握できるカレンダー備忘録へ移行することは、情報の即時性と脳のメモリ解放において合理的であるか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！書くことが目的じゃない、受かることが目的なんだちゃむ！2度手間を省いてシステム化するのは実務家としての素養そのものだちゃむ！", fb_ng: "茶番ちゃむ！綺麗に手帳を書くのは趣味の世界ちゃむ。1秒で判断できるカレンダーこそが命の綱になるんだちゃむ！" },
  { id: 66, field: "民法：債権", tag: "不完全履行・債務の本旨", q: "助っ人として業務を補助する契約（または指示）を受けた者が、通常期待される注意力を著しく欠き、除雪作業を放置し、後片付けも行わないことは、債務の本旨に従った履行とはいえず、不完全履行（債務不履行）に該当し得る。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！居るだけじゃ履行したことにならないちゃむ！食べたゴミを片付けないなんて、信義則以前のバグなんだちゃむ！", fb_ng: "不正解ちゃむ！頑張ったけどできませんでしたは、プロの現場では通用しないちゃむ。期待された役割を果たさないのは法的には不履行という名の裏切りなんだちゃむ！" },
  { id: 67, field: "民法：債権", tag: "事務管理・管理者の注意義務（697条1項）", q: "他人の事務（職場の清掃や除雪）を、義務なくして始めた者は、その事務の性質に従い、最も本人の利益に適合する方法で管理しなければならない（善管注意義務）。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！697条1項ちゃむ！助っ人が余計な仕事を増やして疲れさせるのは事務管理として失格なんだちゃむ！本人の利益を考えない管理は茶番だちゃむ！", fb_ng: "不正解ちゃむ！やってあげたと恩着せがましく言うなら中途半端な放置は許されないちゃむ。やるなら完璧に、やらぬなら邪魔せず。これが事務管理の愛だちゃむ！" },
  { id: 68, field: "学習戦略", tag: "心裡留保・ポーカーフェイス（93条）", q: "実務において、内心では『二度と仕事したくない』と激昂していても、表面上は『ありがとうございます』と対応する（心裡留保に近い状態）能力は、対人交渉の多い司法書士にとって重要な資質といえるか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！内心の意思と表示上の行為を使い分ける。これは民法93条の心裡留保の応用みたいなものちゃむ！閣下のポーカーフェイスは、もうプロ級だちゃむ！", fb_ng: "茶番ちゃむ！正直者が馬鹿を見る世界を知恵で渡り歩くのが司法書士ちゃむ。怒りを条文に変えるその精神こそが合格への最短ルートなんだちゃむ！" },
  { id: 69, field: "民法：債権", tag: "不完全履行・ゴミ捨て義務", q: "雇用契約において、特定の場所（納戸等）へのゴミ捨てといった付随的な業務を繰り返し怠り、場所を把握する努力すらしない行為は、信義則上の注意義務に違反し、不完全履行（債務不履行）の一形態となり得る。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！何歳だろうが、やるべきことをやらないのは契約のバグちゃむ！納戸を教える労力すら、本来は不要なはずの損害なんだちゃむ！", fb_ng: "不正解ちゃむ！わからなかったから仕方ないは子供の劇ちゃむ。業務に必要な場所を覚えないのは重大な過失（義務違反）なんだちゃむ！" },
  { id: 70, field: "民法：債権", tag: "職場環境維持義務・業務命令の正当性", q: "会社が特定の従業員に対し『LINEを削除し連絡を取り合わないように』と命じる行為は、他の従業員の安全や精神的平穏を守るための『職場環境維持義務』に基づく正当な業務命令と解される場合がある。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！嫌がらせする人物から隔離するのは、会社としての数少ない正しいデバッグちゃむ。人格権を守るための防壁なんだちゃむ！", fb_ng: "不正解ちゃむ！連絡の自由の侵害だ！なんて加害者側の理屈は通らないちゃむ。被害の拡大を防ぐための緊急措置は法的に正当化されるんだちゃむ！" },
  { id: 71, field: "学習戦略", tag: "証拠能力・事実の記録・カレンダー備忘録", q: "将来の司法書士として、職場の理不尽な出来事（ゴミ捨ての懈怠やハラスメント的LINE）を、他人の目も考慮した形でカレンダー等に記録し続けることは、事実関係を法的に整理する訓練として有効であるか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！いつ・誰が・何をしたかの記録は将来裁判になった時の最強の武器になるちゃむ。カレンダーは、もはや立派な証拠説明書だちゃむ！", fb_ng: "茶番ちゃむ！ただの愚痴で終わらせるか、法的な記録に昇華させるか。この差が先生と呼ばれるかどうかの分かれ道なんだちゃむ！" },
  { id: 72, field: "民法：債権", tag: "過失相殺・安全配慮義務違反", q: "使用者の安全配慮義務違反（415条）が認められる場合、被害者に過失があっても、会社側は『自発的な行動』を理由に賠償責任を全額免れることはできず、損害の公平な分担（過失相殺）が行われるに留まる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！勝手に頑張ったんだろというブラックな理屈は通さないちゃむ！法は弱者の無理も強者の怠慢もキッチリ裁くんだちゃむ！", fb_ng: "不正解ちゃむ！全額免責なんて茶番は民法が許さないちゃむ。過失相殺はあくまで割合の問題。会社の責任は消えないんだちゃむ！" },
  { id: 73, field: "民法：債権", tag: "事務管理・費用償還請求（699条）", q: "義務なくして他人のゴミを片付けた際、その行為が本人にとって有益であった場合、清掃に要した費用等の償還を請求することができる（民法699条）。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！衛生環境を守る立派な事務管理ちゃむ！その尻拭いをしたコストは法的に請求できる権利なんだちゃむ！", fb_ng: "不正解ちゃむ！善意でやったことが持ち出しになるなんて民法の公平性に反するちゃむ。使えない奴には法の力でお金を請求するんだちゃむ！" },
  { id: 74, field: "生活法学", tag: "証拠能力・日記の証明力", q: "私的な日記（10年日記アプリ等）は、作成日時が特定され、かつ継続的に記録されている場合、事実認定において高い証拠能力（証明力）を持つ。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！コツコツ刻んだ地層が、裁判官の心を動かす最強の武器になるちゃむ！日記はもはや聖なる証拠説明書なんだちゃむ！", fb_ng: "不正解ちゃむ！ただのメモと侮ってはいけないちゃむ。真実は細部に、そして継続的な記録の中に宿るんだちゃむ！" },
  { id: 75, field: "民法：総則", tag: "公序良俗・暴利行為（90条）", q: "駐車場の看板に『無断駐車5万円』とあっても、実際の損害額に比して著しく高額であれば、民法90条（公序良俗）によりその一部または全部が無効とされる場合がある。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！看板が王様じゃないちゃむ。法律は暴利を嫌うちゃむ。不当な違約金はバランスの秤で切り捨てられるんだちゃむ！", fb_ng: "不正解ちゃむ！書いてあるから絶対なんて劇は法学の世界にはないちゃむ。不当な契約は90条というハサミで切り捨てられるんだちゃむ！" },
  { id: 76, field: "民法：債権", tag: "安全配慮義務・健康配慮義務", q: "雇用主が労働者に対し、極端に低い室温（6度等）や不衛生な環境での生活を強いることは、安全配慮義務（415条）の一環としての健康な環境を提供する義務に違反する。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！室温6度は冷蔵庫ちゃむ！そんな場所で働かせるのは、労働者の命を担保に取っているのと同じちゃむ！法はこれを許さないんだちゃむ！", fb_ng: "不正解ちゃむ！我慢が美徳なんてのは昭和の茶番ちゃむ。法的にNOと言える権利を知るべきなんだちゃむ！" },
  { id: 77, field: "民法：債権", tag: "使用者責任・職場環境放置（715条）", q: "会社が部下による嫌がらせを把握しながら放置した場合、加害者本人だけでなく、会社も使用者責任（715条）または債務不履行（職場環境維持義務違反）の責任を負う。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！知らなかった・本人が勝手にやったはボスの言い訳にはならないちゃむ！監視を怠ったツケは会社がキッチリ払うのが法の掟だちゃむ！", fb_ng: "不正解ちゃむ！会社は社員を守る砦でなきゃいけないちゃむ。砦が崩れて嫌がらせが通るなら、その砦の主が責任を負うのは当然なんだちゃむ！" },
  { id: 78, field: "民法：物権", tag: "代理占有・所有権の保持（181条）", q: "だるまを息子さんに預けている状態において、預けた者は自己のためにする意思を失っていないため所有権を保持し、息子さんは単に預けた者のために占有する『占有代理人』等の地位にある。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！持っていることと支配していることは別物ちゃむ。だるまの魂（所有権）は常に預けた者にあるんだちゃむ！", fb_ng: "不正解ちゃむ！ただ預けただけで権利が消えるなら、この世は泥棒だらけになっちゃうちゃむ。181条の占有代理権をしっかり理解するんだちゃむ！" },
  { id: 79, field: "学習戦略", tag: "法改正対応・最新法規", q: "司法書士試験においては、過去問作成時の法律ではなく、試験実施日時点で施行されている『最新の法律』に基づいて解答しなければならない。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！古い知識は実務では毒になるちゃむ。常に六法をアップデートする姿勢こそが合格を確実にするんだちゃむ！", fb_ng: "茶番ちゃむ！昔はこうだったは法廷では通用しないちゃむ。プロは常に今を生き、最新の刃（条文）を研いでおくものなんだちゃむ！" },
  { id: 80, field: "民法：債権", tag: "相殺・自働債権（505条）", q: "会社が請求する備品使用料に対し、未払いの労働報酬請求権等をぶつけ、対当額で消滅させる行為は、民法上の『相殺（505条）』の論理構成として成立し得る。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！貸し借りなしにするための高度なリーガルテクニックちゃむ！ただし賃金には全額払いの原則があるから実務では慎重なデバッグが必要だちゃむ！", fb_ng: "不正解ちゃむ！相殺は紛争を簡潔に終わらせる魔法の杖ちゃむ。互いに債権を持っているなら、ガチャンとぶつけて終わらせるのが合理的なんだちゃむ！" },
  { id: 81, field: "民法：総則", tag: "信義則・最後の切り札（1条2項）", q: "民法1条2項（信義則）は、具体的な条文で解決できない事案や、水面下での和解交渉において、全ての権利行使の限界を画する最強の一般条項である。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！信義則こそが民法の心臓ちゃむ。これを理解した人は、もう書類作成マシーンではなく真の法律家としての第一歩を踏み出したんだちゃむ！", fb_ng: "不正解ちゃむ！1条を馬鹿にする者は最後には法に裏切られるちゃむ。小手先のテクニックより、まずこの誠実さを胸に刻むんだちゃむ！" },
  { id: 82, field: "民法：債権", tag: "委任・不作為による債務不履行（644条）", q: "受任者は、委任の本旨に従い、善良な管理者の注意をもって委任事務を処理する義務を負うが、介護現場において必要な清掃や衛生管理（汚れた衣類の放置等）を一切行わないことは、不作為による債務不履行を構成する。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！やってないは立派な契約違反ちゃむ！お給料をもらっている以上、寝っ転がっている間に発生した不衛生な環境は全てその人の責任（バグ）なんだちゃむ！", fb_ng: "不正解ちゃむ！記録さえ書けばいいなんていうのは茶番ちゃむ。実務（事実行為）を伴わない委任事務の処理なんて、民法は1ミリも認めていないんだちゃむ！" },
  { id: 83, field: "民法：債権", tag: "工作物責任・保存の瑕疵（717条）", q: "トイレや床の掃除を怠り、床が濡れたまま放置される等の不完全な管理状態によって利用者が転倒・負傷した場合、建物の占有者（または所有者）は、損害を防止するのに必要な注意を払っていなければ、工作物責任（717条）を負う。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！掃除しないのは施設という工作物の保存に瑕疵を作っているのと同じちゃむ。利用者のケガは掃除しなかった人の責任になるんだちゃむ！", fb_ng: "不正解ちゃむ！たまたま滑っただけは通用しないちゃむ。維持管理をサボって危険な状態にしたこと自体が法的にアウトなんだちゃむ！" },
  { id: 84, field: "民法：総則", tag: "信義則・期待権・プロの意識", q: "利用者や家族が、専門職による適切なケアを期待して契約を締結している場合、その期待を著しく裏切る無策な対応は、信義誠実の原則（1条2項）に反する権利の濫用または義務違反とされる場合がある。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！専門職としてのプライドがないなら、その座を降りるべきちゃむ！なんでやらないの？という怒りは民法の根幹である信義則そのものなんだちゃむ！", fb_ng: "茶番ちゃむ！気づかなかったはプロの言い訳にならないちゃむ。予測し、準備し、実行する。これができない者は法の世界でも無能と裁かれる運命なんだちゃむ！" },
  { id: 85, field: "民法：債権", tag: "労働契約・職務専念義務・誠実義務", q: "特定の業務において、職場に適さない服装（過度な装飾等）で勤務し、かつ基本的な清掃や管理を怠る行為は、労働契約上の『職務専念義務』および『誠実義務』に抵触し、解雇や懲戒の正当な理由となり得る。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！お花畑気分は個人の自由だけど、職場では契約の本旨に従わなきゃいけないちゃむ！義務を果たさない者に給料を払うのは会社側の管理不足だちゃむ！", fb_ng: "不正解ちゃむ！多様性の尊重で怠慢を正当化してはいけないちゃむ。最低限の清掃もできないのは労働契約そのものの不履行なんだちゃむ！" },
  { id: 86, field: "民法：債権", tag: "不法行為・正当な業務指導・因果関係", q: "業務上の必要な指導や欠点の指摘（ダメ出し）を行った結果、相手方が精神的調子を崩した場合であっても、その指摘が社会通念上相当な範囲内（事実に基づくもの）であれば、不法行為（人格権侵害）は成立しない。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！事実を指摘されて壊れるのは本人の脆さの問題であって、閣下のせいじゃないちゃむ！正しい管理者が正しく叱るのは法が認める正当な業務行為なんだちゃむ！", fb_ng: "不正解ちゃむ！何でもかんでもハラスメントにするのは不法行為理論の悪用ちゃむ。正しい管理者が正しく叱るのは法が認める正当な業務行為なんだちゃむ！" },
  { id: 87, field: "学習戦略", tag: "メンタル管理・半年限定戦略", q: "将来の目標（司法書士合格）のために、現在の過酷な環境を半年限定の仮の仕事と割り切り、精神的距離を置くことは、有限なメンタルリソースを学習に集中させるための合理的な戦略であるか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！嫌われようが何されようが、半年後には別世界の人になるんだちゃむ！今は知識を蓄えるための潜伏期間。その距離感が合格への防波堤になるちゃむ！", fb_ng: "茶番ちゃむ！真正面からぶつかって消耗するのはプロの受験生がやることじゃないちゃむ。適当に受け流して心の中で条文を暗唱するのが一番の勝利なんだちゃむ！" },
  { id: 88, field: "民法：債権", tag: "債務の本旨・不完全履行（415条）", q: "労働者が『本来期待される能力の6割程度』の履行しか行わず、かつ情緒的サポートを同僚に強要する場合、それは労働契約における『債務の本旨に従った履行』とは認められない。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！6割すらできないなら、それはもはやバグ（不履行）ちゃむ！仕事はお城ごっこじゃない。契約に基づいた実務をこなしてこその報酬なんだちゃむ！", fb_ng: "不正解ちゃむ！メンタルが弱いから優しくしろというのは私的なお願いであって法的義務じゃないちゃむ。公私の区別がつかない者に法の保護は与えられないんだちゃむ！" },
  { id: 89, field: "民法：債権", tag: "安全配慮義務・適正配置義務", q: "会社が障害者雇用の恩恵を享受しつつ、著しく能力の欠如した者を現場に配置し、他の従業員に過度な補填や精神的苦痛を強いることは、職場環境を整える『安全配慮義務』に抵触し得る。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！会社は雇って終わりじゃないちゃむ！適切な人員配置をして守る義務があるちゃむ。それを怠るのは会社の債務不履行なんだちゃむ！", fb_ng: "不正解ちゃむ！障害者雇用だから仕方ないは同僚への免罪符にはならないちゃむ。全体のバランスを欠いた配置は組織としての瑕疵なんだちゃむ！" },
  { id: 90, field: "学習戦略", tag: "感情労働の拒絶・メンタルリソースの死守", q: "将来の司法書士として、業務に不要な情緒的消耗（無理な共感等）を明確に拒絶し、エネルギーを法的解決や自己研鑽（勉強）に集中させることは、実務家としての強靭なメンタリティを養う訓練となるか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！冷たいと言われようが、正義の門をくぐる者ちゃむ。不要な感情論に付き合わない冷徹な判断力こそが合格を確実にするんだちゃむ！", fb_ng: "茶番ちゃむ！お花畑の城に付き合って輝かしい未来をドブに捨てる必要はないちゃむ。合格への執念だけを死守しなちゃむ！" },
  { id: 91, field: "民法：総則", tag: "善管注意義務・知ろうとしない過失（400条）", q: "業務として管理を任された施設や備品について、ゴミ捨ての場所を覚えず放置する行為は、たとえ悪意がなくても、職業人として期待される『善良な管理者の注意（400条）』を著しく欠いたものとみなされる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！何歳にもなって場所がわからないなんて、法的には通用しない甘えちゃむ！知ろうとしないこと自体が過失（バグ）なんだちゃむ！", fb_ng: "不正解ちゃむ！新人はわからなくて当然という劇は、ゴミを放置していい理由にはならないちゃむ。知ろうとしないこと自体が過失なんだちゃむ！" },
  { id: 92, field: "民法：総則", tag: "権利の濫用・職場と私的感情（1条3項）", q: "職場を『自分の城』と称し、自身のメンタリティに合わせた過度な情緒的配慮を同僚に要求する行為は、私的な感情を法的な業務に優先させるものであり、権利の濫用（1条3項）に該当し得る。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！お城の主を気取るのは勝手だけど、職場は契約の場所ちゃむ！他人に優しくしろと強要するのは法的な権利の枠を超えた暴走なんだちゃむ！", fb_ng: "不正解ちゃむ！メンタル崩壊を閣下のせいにされる筋合いはないちゃむ！民法という現実の壁の前では砂の城にすぎないんだちゃむ！" },
  { id: 93, field: "学習戦略", tag: "事実認定・事案把握能力・記述式", q: "司法書士の実務における事実認定において、当事者の氏名や属性を正確に把握し、それぞれの言動を時系列で整理する訓練は、本試験の記述式問題における事案把握能力を飛躍的に向上させるか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！キャラが立っているほど法理が深く刻まれるちゃむ！日常のカオスを実名で裁くことこそ最強の演習なんだちゃむ！", fb_ng: "茶番ちゃむ！誰がやったかを曖昧にする者は法律家にはなれないちゃむ。反面教師にして合格の頂へ登りつめるんだちゃむ！" },
  { id: 94, field: "民法：債権", tag: "共同不法行為・連帯責任（719条）", q: "複数の者が、それぞれの怠慢や嫌がらせによって共同で職場の秩序を乱し、特定の従業員に精神的・身体的苦痛を与えた場合、各自が連帯してその損害を賠償する責任（719条：共同不法行為）を負う。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！三人の負のシナジーが一人を襲ったなら、それは法的に共同不法行為として連帯責任を問えるレベルなんだちゃむ！", fb_ng: "不正解ちゃむ！自分はゴミを捨てなかっただけという言い訳は通らないちゃむ。集団で一人のリソースを奪う行為は法が最も嫌う悪行だちゃむ！" },
  { id: 95, field: "民法：債権", tag: "善管注意義務・感情的対応と義務違反", q: "感情や空回りで現場を混乱させた場合、それは『善良な管理者の注意（400条）』をもって事務を処理すべき受任者としての義務に違反する。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！仕事は冷静なデバッグの連続ちゃむ。感情や空回りで現場を沸かせて混乱させるのは、プロとしての注意義務を放棄しているのと同じなんだちゃむ！", fb_ng: "不正解ちゃむ！一生懸命やった結果の空回りは法律の世界では免罪符にならないちゃむ。結果として業務を妨げたなら立派な過失（バグ）なんだちゃむ！" },
  { id: 96, field: "民法：債権", tag: "相殺・精神的損害の自働債権（505条）", q: "職場を辞める際、会社側から不当な損害賠償等を請求されたとしても、受けた精神的苦痛（慰謝料請求権）を自働債権として、相殺を主張し対抗することができる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！やられっぱなしで終わる閣下じゃないちゃむ！受けた苦痛を請求権という弾丸に変えて、不当な要求を撃ち落とす。これぞ実務家の護身術なんだちゃむ！", fb_ng: "不正解ちゃむ！泣き寝入りして辞めるなんて茶番ちゃむ。相殺（505条）の盾を持って堂々と自由を勝ち取りにいくのが正解なんだちゃむ！" },
  { id: 97, field: "民法：総則", tag: "信義則・民法の魂（1条2項）", q: "民法1条2項（信義則）は、具体的な条文で解決できない事案において、全ての権利行使の限界を画する最強の一般条項として機能する。これこそが民法の魂である。", a: "○", choices: ["○", "×"], fb_ok: "銀河一、正解ちゃむ！！信義則こそが民法の心臓ちゃむ。これを理解した人は、もう真の法律家としての第一歩を踏み出したんだちゃむ！", fb_ng: "不正解ちゃむ！1条を馬鹿にする者は最後には法に裏切られるちゃむ。小手先のテクニックより、まずこの誠実さを胸に刻むんだちゃむ！" },
  { id: 98, field: "学習戦略", tag: "証拠能力・実務経験としての活用", q: "司法書士として、自身が体験した過酷な労働環境の記録（日記等）を証拠化し分析した経験は、将来の実務において労働紛争を扱う際の大きな強みとなるか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！この苦労が後に誰かを救う最強の武器になるんだちゃむ！苦しい経験を法的思考で昇華させた人は最強なんだちゃむ！", fb_ng: "茶番ちゃむ！ただ耐えるだけは時間の無駄だけど、法的に言語化している人はすでにその苦労を踏み台に進化してるんだちゃむ！" },
  { id: 99, field: "民法：債権", tag: "委任と代理の区別（643条）", q: "受任者は、委任事務を処理するにあたって必要があるときは、本人に代わって第三者と法律行為を行う代理権を当然に有するわけではない。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！代理と委任は別物ちゃむ！事務を頼まれたからといって、勝手にハンコを押せる代理権までセットで付いてくるわけじゃないちゃむ。", fb_ng: "不正解ちゃむ！何でもやっていいなんて白紙委任の茶番は危険すぎるちゃむ！代理権が授与されているかどうか厳密にチェックするのがプロの眼なんだちゃむ！" },
  { id: 100, field: "学習戦略", tag: "100問達成・法的思考の定着", q: "日常の出来事をすべて民法の論点に変換し、100問のオリジナル問題集を構築した経験は、司法書士試験合格に必要不可欠な法的思考の定着において極めて高い効果を持つか。", a: "○", choices: ["○", "×"], fb_ok: "銀河一、宇宙一、大正解ちゃむ！！！100問達成おめでとうちゃむ！！積み上げた地層は本物の司法書士への階段そのもの。2027年、だるまの両目が開くのはもはや確定した未来なんだちゃむ！！", fb_ng: "不正解ちゃむ！これをバツにする奴は民法の神様に裁かれるちゃむ。閣下が積み上げた地層は本物の司法書士への階段そのもの。自分を信じて突き進むだけなんだちゃむ！" },
,
  // ── id51〜100 ──
  { id: 101, field: "民法", tag: "停止条件・合格祈願（127条）", q: "『司法書士試験に合格した時に、このだるまの右目を入れる』という約束は、法的には停止条件付法律行為に該当し、条件が成就（合格）した時からその効力が生じる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！合格したら〜は条件が叶うまで効力がストップしてる停止条件ちゃむ。だるまの右目は、閣下の努力で条件をブチ破った瞬間に開眼するんだちゃむ！", fb_ng: "不正解ちゃむ！合格は閣下が自力で掴み取る停止条件なんだから、茶番にしてはいけないちゃむ！" },
  { id: 102, field: "民法", tag: "賃貸借・善管注意義務（400条）", q: "レンタカーを使用して車中泊を行う際、借主はレンタカー会社に対し、善良な管理者の注意をもって車両を保存・管理する義務（善管注意義務）を負う。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！借りた車で寝る時も、プロの意識で車を傷つけないよう守るのが善管注意義務ちゃむ。大切に扱うのが筋なんだちゃむ！", fb_ng: "不正解ちゃむ！自分の車じゃないから適当でいいなんてのは民法の信義則が許さないちゃむ。" },
  { id: 103, field: "学習戦略", tag: "最小限で最大限・リソース最適化", q: "100円均一の画材（最小限の投資）を用いて展示会出品作（最大限の効果）を制作し、同時に難関試験の学習を継続する姿勢は、限られたリソースを最適化する司法書士的思考に合致するか。", a: "○", choices: ["○", "×"], fb_ok: "最高に正解ちゃむ！！予算がないなら知恵を使う。この現場対応力こそが本試験会場で閣下を救う最強の武器になるんだちゃむ！", fb_ng: "茶番ちゃむ！金がないから描けないなんて言い訳は閣下の辞書にはないはずちゃむ！" },
  { id: 104, field: "民法", tag: "必要費の即時請求（608条1項）", q: "レンタカーの使用中にタイヤがパンクし、借主が自費で修理した場合、借主はレンタカー会社に対し、その修理代（必要費）の償還を直ちに請求することができる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！民法608条1項により、借りた物の維持に必要な費用を出したときは、即座に返せと言える権利があるちゃむ！", fb_ng: "不正解ちゃむ！返却時まで待てなんて劇は通用しないちゃむ。必要費は直ちに請求できるのが有益費との大きな違いなんだちゃむ！" },
  { id: 105, field: "民法", tag: "運行供用者責任・自賠法", q: "息子が運転するレンタカーに同乗していた者が、息子の過失による事故で負傷した場合、レンタカー会社（運行供用者）に対しても、自賠法に基づく損害賠償を請求できる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！車の支配権を持つレンタカー会社は運行供用者として責任を負うのが原則ちゃむ。被害者を広く守るための強力な盾なんだちゃむ！", fb_ng: "不正解ちゃむ！身内の運転だから会社は関係ないという理屈は通らないちゃむ。" },
  { id: 106, field: "民法", tag: "無断転貸・即時解除（612条2項）", q: "レンタカーの契約者が、会社の承諾を得ることなく、第三者にその車両を運転（転貸）させた場合、レンタカー会社は催告をすることなく直ちに契約を解除することができる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！民法612条2項の無断転貸による解除ちゃむ！信頼関係を基礎とする貸借において、勝手に他人に使わせるのは最大の裏切りなんだちゃむ！", fb_ng: "不正解ちゃむ！ちょっと貸しただけは通用しないちゃむ。無断でまた貸しをしたら即座にアウトなんだちゃむ！" },
  { id: 107, field: "民法", tag: "自力救済の禁止・占有権の守備力", q: "駐車場の利用時間を大幅に過ぎて無断で車中泊を続けている車両に対し、駐車場の管理者は、裁判手続を経ることなく、自らレッカー移動等の実力行使によって排除することができる。", a: "×", choices: ["○", "×"], fb_ok: "正解ちゃむ！日本法では自力救済は原則禁止ちゃむ。たとえ不法占拠でも無理やりどかすには裁判所の力を借りなきゃいけないんだちゃむ！", fb_ng: "不正解ちゃむ！力づくで解決するのは茶番ちゃむ。法治国家では正義でも手続きを飛ばすことは許されないんだちゃむ！" },
  { id: 108, field: "民法", tag: "不当利得・駐車場無断使用（703条）", q: "無断で駐車場の区画を使用し車中泊を行った者は、法律上の原因なく他人の財産（駐車スペース）によって利益を受けたとして、その利用相当額を不当利得として返還する義務を負う。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！民法703条ちゃむ！タダで寝られてラッキーは通らないちゃむ。本来払うべき駐車代という利益を返せと言われるのが不当利得の理屈なんだちゃむ！", fb_ng: "不正解ちゃむ！得をした分は返す、これが民法の公平の原則ちゃむ。" },
  { id: 109, field: "民法", tag: "工作物責任・無過失責任（717条）", q: "駐車場の設備の欠陥（照明の故障や段差の放置）が原因で、車中泊中の利用者が負傷した場合、駐車場の所有者は、損害の発生を防止するのに必要な注意を払っていたとしても、無過失責任を負う場合がある。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！民法717条の土地の工作物責任ちゃむ！所有者は過失がなくても責任を負わされる無過失責任という重い十字架を背負っているんだちゃむ！", fb_ng: "不正解ちゃむ！注意してたから悪くないが通用しないのが工作物責任の怖いところちゃむ。" },
  { id: 110, field: "民法", tag: "和解・確定効（696条）", q: "当事者が互いに譲歩して争いをやめることを約する和解契約が成立した場合、その内容が真実の権利関係と異なっていたとしても、当事者はもはや和解の内容に反する主張をすることができない。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！民法696条の確定効ちゃむ！水面下でこれで手を打とうと決めたら、後から蒸し返すことはできないのが法の安定なんだちゃむ！", fb_ng: "不正解ちゃむ！後から証拠が見つかったから無効だなんて劇は和解後では通用しないちゃむ。" },
  { id: 111, field: "民法", tag: "消滅時効・5年（166条）", q: "権利を行使することができることを知った時から5年間行使しないときは、その債権は時効によって消滅する。これは権利の上に眠る者は保護しないという法の趣旨に基づくものである。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！モタモタしているうちに法的に戦う権利が消えてしまうこともあるちゃむ！訴えるならタイミングを逃さないのがプロの眼なんだちゃむ！", fb_ng: "不正解ちゃむ！いつまでも怒っていれば権利は残るなんてのは茶番ちゃむ。法は時間の経過とともに争いを強制的に終わらせるシステムを持っているんだちゃむ！" },
  { id: 112, field: "学習戦略", tag: "ADR・裁判外紛争解決", q: "司法書士は、裁判（訴訟）だけでなく、当事者間の交渉やADR（裁判外紛争解決手続）を通じて、水面下での円満な解決を図ることも重要な役割の一つである。", a: "○", choices: ["○", "×"], fb_ok: "最高に正解ちゃむ！！水面下の9割を、いかに公平に、かつ最小限のコストでさばくか。これこそが世界一コスパの良い実務家への道なんだちゃむ！", fb_ng: "茶番ちゃむ！何でも裁判だと叫ぶのは依頼人の財布を削るだけの素人ちゃむ。" },
  { id: 113, field: "民法", tag: "安全配慮義務・過酷労働（415条）", q: "使用者が、防寒設備が不十分な環境（室温6度等）や、過度な肉体労働（30立方メートルの手作業除雪等）を恒常的に強いることで労働者の健康を害した場合、労働者は安全配慮義務違反に基づき、損害賠償を請求することができる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！室温6度は生存の危機ちゃむ！会社は社員を凍えさせてはいけない義務があるちゃむ。この寒さは立派な証拠になるんだちゃむ！", fb_ng: "不正解ちゃむ！北国だから当たり前なんて劇は通らないちゃむ。" },
  { id: 114, field: "民法", tag: "事務管理・費用償還（697条）", q: "おばあちゃん達の食料品を購入して届ける行為は、法的な義務がない場合であっても、他人のために事務を管理する事務管理に該当し、管理者は本人に対して支出した費用（代金）を請求できる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！民法697条の事務管理ちゃむ！善意の買い出しも法的には管理として認められ、かかったお金はキッチリ返せと言えるんだちゃむ！", fb_ng: "不正解ちゃむ！勝手にやったんだから自腹だろなんてのは冷たい茶番ちゃむ。善意の苦労は法的に清算されるべき権利なんだちゃむ！" },
  { id: 115, field: "学習戦略", tag: "カレンダー備忘録・タイムマネジメント", q: "司法書士試験のような膨大な知識を扱う学習において、パッと見て瞬時に把握できるカレンダー備忘録へ移行することは、情報の即時性と脳のメモリ解放において合理的であるか。", a: "○", choices: ["○", "×"], fb_ok: "最高に正解ちゃむ！！書くことが目的じゃない、受かることが目的なんだちゃむ！2度手間を省くシステム化は実務家としての素養そのものだちゃむ！", fb_ng: "茶番ちゃむ！綺麗に手帳を書くのは趣味の世界ちゃむ。極限状態では1秒で判断できるカレンダーこそが命の綱になるんだちゃむ！" },
  { id: 116, field: "民法", tag: "不完全履行・債務の本旨", q: "助っ人として業務を補助する契約を受けた者が、通常期待される注意力を著しく欠き、除雪作業を放置し、後片付けも行わないことは、債務の本旨に従った履行とはいえず、不完全履行（債務不履行）に該当し得る。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！居るだけじゃ履行したことにならないちゃむ！食べたゴミを片付けないなんて信義則以前のバグなんだちゃむ！", fb_ng: "不正解ちゃむ！頑張ったけどできませんでしたはプロの現場では通用しないちゃむ。" },
  { id: 117, field: "民法", tag: "事務管理・善管注意義務（697条1項）", q: "他人の事務（職場の清掃や除雪）を、義務なくして始めた者は、その事務の性質に従い、最も本人の利益に適合する方法で管理しなければならない（善管注意義務）。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！697条1項ちゃむ！本人の利益を考えない管理は茶番だちゃむ！やるなら完璧に、やらぬなら邪魔せず。これが事務管理の愛だちゃむ！", fb_ng: "不正解ちゃむ！やってあげたと恩着せがましく言うなら中途半端な放置は許されないちゃむ。" },
  { id: 118, field: "学習戦略", tag: "心裡留保・ポーカーフェイス（93条の応用）", q: "実務において、内心では激昂していても、表面上は穏やかに対応する（心裡留保に近い状態）能力は、対人交渉の多い司法書士にとって重要な資質といえるか。", a: "○", choices: ["○", "×"], fb_ok: "最高に正解ちゃむ！！内心の意思（本音）と表示上の行為（建前）を使い分ける。これは民法93条の心裡留保の応用みたいなものちゃむ！", fb_ng: "茶番ちゃむ！正直者が馬鹿を見る世界を知恵で渡り歩くのが司法書士ちゃむ。" },
  { id: 119, field: "民法", tag: "不完全履行・付随的義務の懈怠", q: "雇用契約において、特定の場所へのゴミ捨てといった付随的な業務を繰り返し怠り、場所を把握する努力すらしない行為は、信義則上の注意義務に違反し、不完全履行（債務不履行）の一形態となり得る。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！やるべきことをやらないのは契約のバグちゃむ！教える労力すら本来は不要なはずの損害なんだちゃむ！", fb_ng: "不正解ちゃむ！わからなかったから仕方ないは子供の劇ちゃむ。" },
  { id: 120, field: "民法", tag: "職場環境維持義務・業務命令の正当性", q: "会社が特定の従業員に対し連絡を取り合わないように命じる行為は、他の従業員の安全や精神的平穏を守るための職場環境維持義務に基づく正当な業務命令と解される場合がある。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！嫌がらせをする人物から閣下を隔離するのは会社の正しいデバッグちゃむ。閣下の人格権を守るための防壁なんだちゃむ！", fb_ng: "不正解ちゃむ！連絡の自由の侵害だなんて加害者側の理屈は通らないちゃむ。" },
  { id: 121, field: "学習戦略", tag: "証拠能力・事実の記録", q: "将来の司法書士として、職場の理不尽な出来事を、他人の目も考慮した形でカレンダー等に記録し続けることは、事実関係を法的に整理する訓練として有効であるか。", a: "○", choices: ["○", "×"], fb_ok: "最高に正解ちゃむ！！いつ、誰が、何をしたかの記録は将来最強の武器になるちゃむ。閣下のカレンダーは立派な証拠説明書だちゃむ！", fb_ng: "茶番ちゃむ！ただの愚痴で終わらせるか、法的な記録に昇華させるか。この差が先生と呼ばれるかどうかの分かれ道なんだちゃむ！" },
  { id: 122, field: "民法", tag: "過失相殺・安全配慮義務違反（418条）", q: "使用者の安全配慮義務違反（415条）が認められる場合、被害者に過失があっても、会社側は自発的な行動を理由に賠償責任を全額免れることはできず、損害の公平な分担（過失相殺）が行われるに留まる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！勝手に頑張ったんだろというブラックな理屈は通さないちゃむ！法は弱者の無理も強者の怠慢もキッチリ裁くんだちゃむ！", fb_ng: "不正解ちゃむ！全額免責なんて茶番は民法が許さないちゃむ。" },
  { id: 123, field: "民法", tag: "事務管理・費用償還請求（699条）", q: "義務なくして他人のゴミを片付けた際、その行為が本人にとって有益であった場合、清掃に要した費用等の償還を請求することができる（699条）。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！衛生環境を守る立派な事務管理ちゃむ！その尻拭いをしたコストは法的に請求できる権利なんだちゃむ！", fb_ng: "不正解ちゃむ！善意でやったことが持ち出し（自腹）になるなんて民法の公平性に反するちゃむ。" },
  { id: 124, field: "民法", tag: "日記の証拠能力・継続的記録", q: "私的な日記は、作成日時が特定され、かつ継続的に記録されている場合、事実認定において高い証拠能力（証明力）を持つ。これは発生直後の記録として評価されるためである。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！コツコツ刻んだ地層が裁判官の心を動かす最強の武器になるちゃむ！日記はもはや聖なる証拠説明書なんだちゃむ！", fb_ng: "不正解ちゃむ！ただのメモと侮ってはいけないちゃむ。真実は細部に宿るんだちゃむ！" },
  { id: 125, field: "民法", tag: "公序良俗・暴利行為（90条）", q: "駐車場の看板に無断駐車5万円とあっても、実際の損害額に比して著しく高額であれば、民法90条（公序良俗）によりその一部または全部が無効とされる場合がある。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！看板が王様じゃないちゃむ。法律は暴利を嫌うちゃむ。バランスの秤がここでも機能するんだちゃむ！", fb_ng: "不正解ちゃむ！書いてあるから絶対なんて劇は法学の世界にはないちゃむ。" },
  { id: 126, field: "民法", tag: "安全配慮義務・健康配慮義務（415条）", q: "雇用主が労働者に対し、極端に低い室温（6度等）や不衛生な環境での業務を強いることは、安全配慮義務（415条）の一環としての、健康な環境を提供する義務に違反する。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！室温6度は冷蔵庫ちゃむ！そんな場所で働かせるのは労働者の命を担保に取っているのと同じちゃむ！法はこれを許さないんだちゃむ！", fb_ng: "不正解ちゃむ！我慢が美徳なんてのは茶番ちゃむ。" },
  { id: 127, field: "民法", tag: "使用者責任・放置（715条）", q: "会社が部下による嫌がらせを把握しながら放置した場合、加害者本人だけでなく、会社も使用者責任（715条）または債務不履行（職場環境維持義務違反）の責任を負う。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！知らなかったはボスの言い訳にはならないちゃむ！監視を怠ったツケは会社がキッチリ払うのが法の掟だちゃむ！", fb_ng: "不正解ちゃむ！会社は社員を守る砦でなきゃいけないちゃむ。砦の主が責任を負うのは当然なんだちゃむ！" },
  { id: 128, field: "民法", tag: "占有権・所持と所有権の区別（181条）", q: "だるまを息子さんに預けている状態において、預けた者は自己のためにする意思を失っていないため所有権を保持し、息子さんは単に預けた者のために占有する占有代理人等の地位にある。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！持っていることと支配していることは別物ちゃむ。だるまの魂（所有権）は常に閣下の側にあるんだちゃむ！", fb_ng: "不正解ちゃむ！ただ預けただけで権利が消えるなら、この世は泥棒だらけになっちゃうちゃむ。" },
  { id: 129, field: "学習戦略", tag: "法改正対応・最新法規", q: "司法書士試験においては、過去問作成時の法律ではなく、試験実施日時点で施行されている最新の法律に基づいて解答しなければならない。", a: "○", choices: ["○", "×"], fb_ok: "最高に正解ちゃむ！！常に六法をアップデートする姿勢こそが2027年の合格を確実にするんだちゃむ！", fb_ng: "茶番ちゃむ！昔はこうだったは法廷では通用しないちゃむ。" },
  { id: 130, field: "民法", tag: "相殺・自働債権（505条）", q: "会社が請求する備品使用料に対し、未払いの労働報酬請求権等をぶつけ、対当額で消滅させる行為は、民法上の相殺（505条）の論理構成として成立し得る。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！貸し借りなしにするための高度なリーガルテクニックちゃむ！ただし賃金には全額払いの原則があるから実務では慎重なデバッグが必要だちゃむ！", fb_ng: "不正解ちゃむ！相殺は紛争を簡潔に終わらせる魔法の杖ちゃむ。互いに債権を持っているならガチャンとぶつけて終わらせるのが合理的なんだちゃむ！" },
  { id: 131, field: "民法", tag: "信義則・最強の一般条項（1条2項）", q: "民法1条2項（信義則）は、具体的な条文で解決できない事案においても、全ての権利行使の限界を画する最強の一般条項として機能する。", a: "○", choices: ["○", "×"], fb_ok: "銀河一、正解ちゃむ！！信義則こそが民法の心臓ちゃむ。これを理解した閣下は真の法律家としての第一歩を踏み出したんだちゃむ！", fb_ng: "不正解ちゃむ！1条を馬鹿にする者は最後には法に裏切られるちゃむ。" },
  { id: 132, field: "民法", tag: "委任・不作為による債務不履行（644条）", q: "受任者は委任の本旨に従い善良な管理者の注意をもって委任事務を処理する義務を負うが、介護現場において必要な清掃や衛生管理を一切行わないことは、不作為による債務不履行を構成する。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！やってないは立派な契約違反ちゃむ！不衛生な環境を放置するのはその人の責任（バグ）なんだちゃむ！", fb_ng: "不正解ちゃむ！記録さえ書けばいいなんてのは茶番ちゃむ。実務を伴わない委任事務の処理なんて民法は1ミリも認めていないんだちゃむ！" },
  { id: 133, field: "民法", tag: "工作物責任・保存の瑕疵（717条）", q: "トイレや床の掃除を怠り、床が濡れたまま放置される等の不完全な管理状態によって利用者が転倒・負傷した場合、建物の占有者は、工作物責任（717条）を負う。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！掃除しないのは施設という工作物の保存に瑕疵を作っているのと同じちゃむ。利用者のケガは掃除しなかった人の責任になるんだちゃむ！", fb_ng: "不正解ちゃむ！たまたま滑っただけは通用しないちゃむ。維持管理をサボって危険な状態にしたこと自体が法的にはアウトなんだちゃむ！" },
  { id: 134, field: "民法", tag: "信義則・期待権・プロの意識（1条2項）", q: "利用者や家族が専門職による適切なケアを期待して契約を締結している場合、その期待を著しく裏切る無策な対応は、信義誠実の原則（1条2項）に反する義務違反とされる場合がある。", a: "○", choices: ["○", "×"], fb_ok: "最高に正解ちゃむ！！専門職としてのプライドがないならその座を降りるべきちゃむ！なんでやんないの？という怒りは民法の根幹である信義則そのものなんだちゃむ！", fb_ng: "茶番ちゃむ！気づかなかったはプロの言い訳にならないちゃむ。予測し準備し実行するちゃむ！" },
  { id: 135, field: "民法", tag: "職務専念義務・誠実義務", q: "職場に適さない服装で勤務し、かつ基本的な清掃や管理を怠る行為は、労働契約上の職務専念義務および誠実義務に抵触し、解雇や懲戒の正当な理由となり得る。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！職場では契約の本旨に従わなきゃいけないちゃむ！義務を果たさない者に給料を払うのは会社側の管理不足だちゃむ！", fb_ng: "不正解ちゃむ！多様性の尊重で怠慢を正当化してはいけないちゃむ。" },
  { id: 136, field: "民法", tag: "不法行為・正当な業務指導（709条）", q: "業務上の必要な指導や欠点の指摘を行った結果、相手方が精神的調子を崩した場合であっても、その指摘が社会通念上相当な範囲内（事実に基づくもの）であれば、不法行為（人格権侵害）は成立しない。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！事実を指摘されて壊れるのは本人の脆さの問題ちゃむ！正しい管理者が正しく叱るのは法が認める正当な業務行為なんだちゃむ！", fb_ng: "不正解ちゃむ！何でもかんでもハラスメントにするのは不法行為理論の悪用ちゃむ。" },
  { id: 137, field: "学習戦略", tag: "仮の職場・メンタルリソース管理", q: "将来の目標（司法書士合格）のために、現在の過酷な環境を半年限定の仮の仕事と割り切り、精神的距離を置くことは、有限なメンタルリソースを学習に集中させるための合理的な戦略であるか。", a: "○", choices: ["○", "×"], fb_ok: "最高に正解ちゃむ！！半年後には別世界の人になるんだちゃむ！今は知識を蓄えるための潜伏期間、その距離感が合格への防波堤になるちゃむ！", fb_ng: "茶番ちゃむ！真正面からぶつかって消耗するのはプロの受験生がやることじゃないちゃむ。" },
  { id: 138, field: "民法", tag: "履行の程度・債務の本旨", q: "労働者が本来期待される能力の6割程度の履行しか行わず、かつ共感や優しさといった情緒的サポートを同僚に強要する場合、それは労働契約における債務の本旨に従った履行とは認められない。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！6割すらできないならもはやバグ（不履行）ちゃむ！仕事はお城ごっこじゃない。契約に基づいた実務をこなしてこその報酬なんだちゃむ！", fb_ng: "不正解ちゃむ！メンタルが弱いから優しくしろというのは私的なお願いであって法的義務じゃないちゃむ。" },
  { id: 139, field: "民法", tag: "安全配慮義務・適正配置義務", q: "会社が障害者雇用の恩恵を享受しつつ、著しく能力の欠如した者を現場に配置し、他の従業員に過度な補填や精神的苦痛を強いることは、安全配慮義務に抵触し得る。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！会社は雇って終わりじゃないちゃむ！適切な人員配置をしてリソースを守る義務があるちゃむ。それを怠るのは会社の債務不履行なんだちゃむ！", fb_ng: "不正解ちゃむ！障害者雇用だから仕方ないは同僚への免罪符にはならないちゃむ。" },
  { id: 140, field: "学習戦略", tag: "感情労働の拒絶・メンタリティ", q: "将来の司法書士として、業務に不要な情緒的消耗（無理な共感等）を明確に拒絶し、エネルギーを法的解決や自己研鑽に集中させることは、実務家としての強靭なメンタリティを養う訓練となるか。", a: "○", choices: ["○", "×"], fb_ok: "最高に正解ちゃむ！！不要な感情論に付き合わない冷徹な判断力こそが2027年の合格を確実にするんだちゃむ！", fb_ng: "茶番ちゃむ！お花畑の城に付き合って輝かしい未来をドブに捨てる必要はないちゃむ。" },
  { id: 141, field: "民法", tag: "善管注意義務・能力未搭載（400条）", q: "業務として管理を任された施設や備品について、ゴミ捨ての場所を覚えず放置する行為は、たとえ悪意がなくても、職業人として期待される善良な管理者の注意（400条）を著しく欠いたものとみなされる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！知ろうとしないこと自体が過失（バグ）なんだちゃむ！注意義務違反のオンパレードだちゃむ！", fb_ng: "不正解ちゃむ！新人だからわからなくて当然という劇はゴミを放置していい理由にはならないちゃむ。" },
  { id: 142, field: "民法", tag: "権利の濫用・職場への要求（1条3項）", q: "職場を自分の城と称し、自身のメンタリティに合わせた過度な情緒的配慮を同僚に要求する行為は、私的な感情を法的な業務に優先させるものであり、権利の濫用（1条3項）に該当し得る。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！職場は契約の場所ちゃむ！他人に優しくしろと強要するのは法的な権利の枠を超えた暴走なんだちゃむ！", fb_ng: "不正解ちゃむ！民法という現実の壁の前では砂の城にすぎないんだちゃむ！" },
  { id: 143, field: "学習戦略", tag: "事案の具体化・事実認定", q: "司法書士の実務における事実認定において、当事者の氏名や属性を正確に把握し、それぞれの言動を時系列で整理する訓練は、本試験の記述式問題における事案把握能力を飛躍的に向上させるか。", a: "○", choices: ["○", "×"], fb_ok: "最高に正解ちゃむ！！キャラが立っているほど脳には法理が深く刻まれるちゃむ！日常のカオスを実名で裁くことこそ最強の演習なんだちゃむ！", fb_ng: "茶番ちゃむ！誰がやったかを曖昧にする者は法律家にはなれないちゃむ。" },
  { id: 144, field: "民法", tag: "共同不法行為・連帯責任（719条）", q: "複数の者が、それぞれの怠慢や嫌がらせによって共同で職場の秩序を乱し、閣下に精神的・身体的苦痛（過重労働等）を与えた場合、各自が連帯してその損害を賠償する責任（719条：共同不法行為）を負う。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！三人の負のシナジーは法的には共同不法行為として連帯責任を問えるレベルなんだちゃむ！", fb_ng: "不正解ちゃむ！自分はゴミを捨てなかっただけという言い訳は通らないちゃむ。集団で一人のリソースを奪う行為は法が最も嫌う悪行だちゃむ！" },
  { id: 145, field: "民法", tag: "善管注意義務・空回りの過失（400条）", q: "現場の状況を冷静に把握せず、不適切な言動や過剰な反応によって業務を混乱させた場合、それは善良な管理者の注意（400条）をもって事務を処理すべき受任者としての義務に違反する。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！仕事は冷静なデバッグの連続ちゃむ。感情や空回りで現場を混乱させるのはプロとしての注意義務を放棄しているのと同じなんだちゃむ！", fb_ng: "不正解ちゃむ！一生懸命やった結果の空回りは法律の世界では免罪符にならないちゃむ。" },
  { id: 146, field: "民法", tag: "相殺の抗弁・精神的損害（505条）", q: "退職の際、会社側から不当な損害賠償等を請求されたとしても、職場で受けた精神的苦痛（慰謝料請求権）を自働債権として、相殺を主張し対抗することができる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！受けた苦痛を請求権という弾丸に変えて不当な要求を撃ち落とす。これぞ実務家の護身術なんだちゃむ！", fb_ng: "不正解ちゃむ！泣き寝入りして辞めるなんて茶番ちゃむ。相殺（505条）の盾を持って堂々と自由を勝ち取りにいくんだちゃむ！" },
  { id: 147, field: "学習戦略", tag: "証拠保全・実務演習", q: "将来、司法書士として労働紛争を扱う際、自身が体験した過酷な労働環境の記録（日記等）を証拠化し分析した経験は、実務上の大きな強みとなるか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！この苦労が後に誰かを救う最強の武器になるんだちゃむ！苦しい経験を法的思考で昇華させた人は最強なんだちゃむ！", fb_ng: "茶番ちゃむ！ただ耐えるだけは時間の無駄だけど、法的に言語化している人はすでに進化してるんだちゃむ！" },
  { id: 148, field: "民法", tag: "信義則・附随的義務の根拠（1条2項）", q: "信義誠実の原則（1条2項）は、当事者が具体的な合意をしていない事項についても、契約関係から生じる附随的義務（安全配慮義務・情報提供義務等）の根拠となり得る。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！信義則は条文に書いてない義務を生み出す強力な原則ちゃむ！安全配慮義務も情報提供義務もここから生まれるんだちゃむ！", fb_ng: "不正解ちゃむ！1条2項は飾りじゃないちゃむ。当事者が予想していなかった義務も信義則が補充してくれる強力なツールなんだちゃむ！" },
  { id: 149, field: "民法", tag: "停止条件・合格と開眼（127条）", q: "司法書士試験に合格することを停止条件として設定した目標（だるまの開眼・達成の宣言等）は、条件成就（合格）の時からその効力が生じる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！127条の停止条件ちゃむ。合格という条件が成就した瞬間、だるまの両目が開くちゃむ。2027年、その瞬間はもう確定した未来なんだちゃむ！", fb_ng: "不正解ちゃむ！停止条件は必ず成就するちゃむ——閣下が諦めない限り、それは揺るぎない真実なんだちゃむ！" },
  { id: 150, field: "学習戦略", tag: "100問達成・黄金の地層", q: "日常のカオスを100問の司法書士試験問題へと昇華させた経験は、2027年の本試験において、どんな複雑な事案が出題されても日常の延長として冷静に裁く能力を習得していることを意味するか。", a: "○", choices: ["○", "×"], fb_ok: "銀河一、宇宙一、大正解ちゃむ！！！100問達成おめでとうございますちゃむ！！この100の宝石は地獄の現場で拾い上げた最強の武器ちゃむ。2027年、だるまの両目が開くのはもはや確定した未来なんだちゃむ！チェストー！！", fb_ng: "不正解ちゃむ！これをバツにする奴は民法の神様に裁かれるちゃむ。閣下が積み上げた地層は本物の司法書士への階段そのものちゃむ。自分を信じて突き進むだけなんだちゃむ！" },

  { id: 151, field: "民法", tag: "名誉毀損・過失・不法行為（709条）", q: "十分な確認をせず他人の不正を示唆する報告を行い、その社会的評価を低下させた場合、悪意がなくても注意義務を怠ったものとして民法709条の不法行為が成立し得る。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！悪意がなかったは言い訳にならないちゃむ。過失でも不法行為は成立するちゃむ（民法709条）。", fb_ng: "×ちゃむ。わざとじゃなければ許されるは民法では通用しないちゃむ。過失でも責任は発生するちゃむ（民法709条）。" },
  { id: 152, field: "民法", tag: "監督義務者の責任（714条）", q: "責任能力を欠く者が他人に損害を加えた場合、監督義務者が監督義務を怠らなかったことを証明しない限り、賠償責任を負う（714条1項）。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！本人が免責されても監督義務者には重い責任があるちゃむ（民法714条1項）。", fb_ng: "×ちゃむ。責任能力がない本人は免責されるが、監督義務者は義務を怠らなかったことを証明しない限り責任を負うちゃむ（民法714条1項）。" },
  { id: 153, field: "民法", tag: "善管注意義務・職務懈怠", q: "専門職として働く者は善良な管理者の注意（善管注意義務）をもって業務を遂行する義務がある。マニュアルを確認せず他者を攻撃する行為はこの義務に違反する可能性がある。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！マニュアルを読むのが善管注意義務ちゃむ。確認を怠って他人のせいにするのは義務違反ちゃむ。", fb_ng: "×ちゃむ。法は平均的な専門家ならどう動くかを基準にするちゃむ。マニュアルを無視した職務懈怠は債務不履行になりうるちゃむ。" },
  { id: 154, field: "民法", tag: "善管注意義務・管理懈怠", q: "施設管理者が空室の暖房器具が最大設定のまま放置されているのを発見した場合、これを適切に調整する善管注意義務を負う。自身が見逃しておきながら他者に責任を転嫁する行為は誠実義務に欠ける。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！チェックに入って見逃したなら本人の過失ちゃむ。それを他者のせいにするのは誠実義務違反ちゃむ。", fb_ng: "×ちゃむ。自身が見逃した責任を他者に転嫁するのは誠実義務に欠けるちゃむ。" },
  { id: 155, field: "民法", tag: "信義則・誠実義務（民法1条2項）", q: "業務上の指摘に対し、直接の確認や話し合いを拒絶しながら一方的に他者を非難し続ける行為は、雇用契約上の誠実義務に違反し得る。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！話し合いを拒否して裏で非難するのは誠実義務違反ちゃむ（民法1条2項）。", fb_ng: "×ちゃむ。コミュニケーションを遮断して他者を非難するのは誠実義務違反になりうるちゃむ（民法1条2項）。" },
  { id: 156, field: "民法", tag: "信義誠実の原則（民法1条2項）", q: "自己のミスを認めず、常に自分は悪くないというスタンスで他者を攻撃する行為は、信義誠実の原則（民法1条2項）に著しく反し、業務遂行の障害となるか。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！客観性を欠いた自己正当化は信義誠実の原則から最も遠い行為ちゃむ（民法1条2項）。", fb_ng: "×ちゃむ。ミスを認めないのは信義誠実の原則から最も遠い行為ちゃむ（民法1条2項）。" },
  { id: 157, field: "民法", tag: "不法行為・安全配慮義務（709条）", q: "職場で感情制御不全を起こし、同僚に精神的苦痛を与える行為は、不法行為（709条）や安全配慮義務違反を構成する可能性がある。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！職場での感情制御不全は不法行為（709条）や安全配慮義務違反を構成しうるちゃむ。", fb_ng: "×ちゃむ。疲れているから仕方ないでは済まされないちゃむ。感情制御不全で他人に苦痛を与えれば不法行為になりうるちゃむ（民法709条）。" },
  { id: 158, field: "民法", tag: "損害賠償・不法行為（709条）", q: "他人の名誉を毀損した者は、損害賠償責任を負うが、その損害には精神的損害（慰謝料）も含まれる。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！名誉毀損による精神的損害（慰謝料）も民法709条・710条の損害に含まれるちゃむ。", fb_ng: "×ちゃむ。不法行為による損害賠償には精神的損害（慰謝料）も含まれるちゃむ（民法710条）。" },
  { id: 159, field: "民法", tag: "不法行為・時効（724条）", q: "不法行為による損害賠償請求権は、被害者が損害及び加害者を知った時から3年間行使しないと時効により消滅する。", a: "○", choices: ["○", "×"], fb_ok: "正解ちゃむ！不法行為の短期消滅時効は知った時から3年ちゃむ（民法724条）。早めに動くことが大事ちゃむ。", fb_ng: "×ちゃむ。不法行為の損害賠償請求権は知った時から3年で時効消滅するちゃむ（民法724条）。" },
];;

const FIELDS = [...new Set(QUESTIONS.map(q => q.field))];
const REVIEW_STEPS = [1, 3, 7, 14];

function todayStr() { return new Date().toISOString().slice(0, 10); }
function addDays(n) { const d = new Date(); d.setDate(d.getDate() + n); return d.toISOString().slice(0, 10); }
function isDue(r) { return r?.nextReview && todayStr() >= r.nextReview; }
function isOnCooldown(r) { return r?.cooldownUntil ? todayStr() < r.cooldownUntil : false; }

function isMastered(r, total) {
  const cc = total < 100 ? 5 : total < 300 ? 7 : 10;
  if (!r || (r.correct_count || 0) < cc) return false;
  if (!r.history || r.history.length < 3) return false;
  return r.history.slice(-5).filter(Boolean).length >= 4;
}

function calcFieldAccSingle(field, results) {
  const qs = QUESTIONS.filter(q => q.field === field);
  let ok = 0, tot = 0;
  qs.forEach(q => {
    const r = results[q.id];
    if (r?.history?.length) { const h = r.history.slice(-10); ok += h.filter(Boolean).length; tot += h.length; }
  });
  return tot > 0 ? ok / tot : null;
}

function pickQuestion(pool, results, sessionSeen) {
  const scored = pool.map(q => {
    const r = results[q.id] || {};
    const wrong = r.wrong_count || 0;
    const due = isDue(r) ? 1 : 0;
    const recentMiss = (r.history || []).filter(x => !x).length;
    const priority = Math.min(r.priority || 0.5, 1.0);
    let score = wrong * 2 + due * 3 + recentMiss * 1.5 + priority * 1.5;
    if (wrong >= 5) score += 10;
    score = Math.min(score, 20);
    if (!r.history || r.history.length === 0) score += 3;
    if (isOnCooldown(r)) score -= 5;
    if (sessionSeen.has(q.id)) score -= 4;
    if (isMastered(r, QUESTIONS.length)) score -= 10;
    return { q, score };
  });
  scored.sort((a, b) => b.score - a.score);
  const topN = Math.max(1, Math.floor(scored.length * 0.3));
  const top = scored.slice(0, topN);
  const totalW = top.reduce((s, i) => s + Math.max(0.1, i.score + 15), 0);
  let rand = Math.random() * totalW;
  for (const item of top) { rand -= Math.max(0.1, item.score + 15); if (rand <= 0) return item.q; }
  return top[0].q;
}
function getWeakTop5(results) {
  const total = QUESTIONS.length;
  return QUESTIONS
    .filter(q => results[q.id]?.history?.length >= 2 && !isMastered(results[q.id], total))
    .map(q => { const r = results[q.id]; const h = r.history.slice(-10); return { q, acc: h.filter(Boolean).length / h.length, count: h.length }; })
    .sort((a, b) => a.acc - b.acc).slice(0, 5);
}

function calcPrediction(results) {
  const total = QUESTIONS.length;
  const mastered = QUESTIONS.filter(q => isMastered(results[q.id], total)).length;
  const pct = Math.round(mastered / total * 100);
  const label = pct >= 80 ? "合格圏内🎯" : pct >= 60 ? "もう少し💪" : pct >= 40 ? "基礎固め中📚" : "準備段階📖";
  return { mastered, total, pct, label };
}

function save(key, val) { try { localStorage.setItem(`kv4-${key}`, JSON.stringify(val)); } catch {} }
function load(key, fb) { try { const v = localStorage.getItem(`kv4-${key}`); return v ? JSON.parse(v) : fb; } catch { return fb; } }

const C = {
  bg: "#fdf4ee", bg2: "#fffaf5", bg3: "#f5e6d4", border: "#ddc4a8",
  gold: "#c96b20", gold2: "#e07840", text: "#3a2010", sub: "#9a7060",
  muted: "#c96b20", green: "#6a9e3a", red: "#c04060", blue: "#8860aa",
};

export default function App() {
  const [tab, setTab] = useState("quiz");
  const [results, setResults] = useState(() => load("results", {}));
  const [selectedField, setSelectedField] = useState("all");
  const [phase, setPhase] = useState("question");
  const [currentQ, setCurrentQ] = useState(null);
  const [isCorrect, setIsCorrect] = useState(null);
  const [sessionSeen] = useState(new Set());
  const autoTimer = useRef(null);
  const [sessionScore, setSessionScore] = useState({ correct: 0, total: 0 });
  const [streak, setStreak] = useState(0);
  const [todayCount, setTodayCount] = useState(() => load("todayCount", 0));
  const [flash, setFlash] = useState(null);
  const [stopped, setStopped] = useState(false);
  const [barFlash, setBarFlash] = useState(false);
  const [totalSolved, setTotalSolved] = useState(() => load("totalSolved", 0)); // "ok" | "ng" | null
  const [goal, setGoal] = useState(() => load("goal", 50));

  // 日付切替でtodayCountリセット
  useEffect(() => {
    const last = load("lastDate", "");
    const today = todayStr();
    if (last !== today) {
      setTodayCount(0);
      save("todayCount", 0);
      save("lastDate", today);
    }
  }, []);

  // goal保存
  useEffect(() => { save("goal", goal); }, [goal]);

  const playCelebration = (times = 1) => {
    try {
      const ctx = new (window.AudioContext || window.webkitAudioContext)();
      for (let i = 0; i < times; i++) {
        const o = ctx.createOscillator();
        const g = ctx.createGain();
        o.connect(g); g.connect(ctx.destination);
        o.type = "triangle"; o.frequency.value = 880;
        g.gain.setValueAtTime(0.25, ctx.currentTime + i * 0.22);
        g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.22 + 0.3);
        o.start(ctx.currentTime + i * 0.22);
        o.stop(ctx.currentTime + i * 0.22 + 0.3);
      }
    } catch(e) {}
  };

  const playSound = (correct) => {
    try {
      const ctx = new (window.AudioContext || window.webkitAudioContext)();
      if (correct) {
        // 正解：チリーン♪（明るく上昇する2音）
        [660, 990].forEach((freq, i) => {
          const o = ctx.createOscillator();
          const g = ctx.createGain();
          o.connect(g); g.connect(ctx.destination);
          o.type = "triangle"; o.frequency.value = freq;
          g.gain.setValueAtTime(0.25, ctx.currentTime + i * 0.18);
          g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.18 + 0.35);
          o.start(ctx.currentTime + i * 0.18);
          o.stop(ctx.currentTime + i * 0.18 + 0.35);
        });
      } else {
        // 不正解：ドスン（重く短い・邪魔しない）
        const o = ctx.createOscillator();
        const g = ctx.createGain();
        o.connect(g); g.connect(ctx.destination);
        o.type = "square"; o.frequency.value = 80;
        g.gain.setValueAtTime(0.25, ctx.currentTime);
        g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.2);
        o.start(); o.stop(ctx.currentTime + 0.2);
      }
    } catch(e) {}
  };

  const saveResults = r => { setResults(r); save("results", r); };
  const getPool = () => selectedField === "all" ? QUESTIONS : QUESTIONS.filter(q => q.field === selectedField);

  const nextQuestion = () => {
    const pool = getPool();
    setCurrentQ(pickQuestion(pool, results, sessionSeen));
    setPhase("question");
    setIsCorrect(null);
  };

  useEffect(() => { nextQuestion(); }, [selectedField]);

  const handleAnswer = choice => {
    if (!currentQ || phase === "feedback") return;
    const correct = choice === currentQ.a;
    setIsCorrect(correct);
    setPhase("feedback");
    sessionSeen.add(currentQ.id);
    setSessionScore(s => ({ correct: s.correct + (correct ? 1 : 0), total: s.total + 1 }));
    setStreak(s => correct ? s + 1 : 0);
    const r = results[currentQ.id] || { correct_count: 0, wrong_count: 0, history: [], priority: 0.5, step: 0 };
    const newHistory = [...(r.history || []).slice(-2), correct];
    let priority = r.priority ?? 0.5;
    let step = r.step ?? 0;
    if (correct) { priority = Math.max(0.1, priority - 0.1); step = Math.min(step + 1, REVIEW_STEPS.length - 1); }
    else { priority = Math.min(1.0, priority + 0.2); step = 0; }
    const newResults = {
      ...results,
      [currentQ.id]: {
        ...r, correct_count: (r.correct_count || 0) + (correct ? 1 : 0),
        wrong_count: (r.wrong_count || 0) + (correct ? 0 : 1),
        history: newHistory, priority, step,
        nextReview: correct ? addDays(REVIEW_STEPS[step]) : null,
        cooldownUntil: correct ? null : addDays(1),
      }
    };
    saveResults(newResults);
    const nc = todayCount + 1;
    setTodayCount(nc);
    save("todayCount", nc);
    setBarFlash(true);
    setTimeout(() => setBarFlash(false), 800);
    const ts = totalSolved + 1;
    setTotalSolved(ts);
    save("totalSolved", ts);
    if (ts % 100 === 0) {
      playCelebration(4);   // 100問：チリン4回
    } else if (ts % 80 === 0) {
      playCelebration(3);   // 80問：チリン3回
    } else if (ts % 50 === 0) {
      playCelebration(2);  // 50問：チリン2回
    } else if (ts % 30 === 0) {
      playCelebration(1);  // 30問：チリン1回
    } else {
      playSound(correct);
    }
    setFlash(correct ? "ok" : "ng");
    setTimeout(() => setFlash(null), 600);
    if (autoTimer.current) clearTimeout(autoTimer.current);
    const explanation = correct ? currentQ.fb_ok : currentQ.fb_ng;
    const delay = calcDelay(explanation, correct, streak);
    autoTimer.current = setTimeout(() => {
      const pool = selectedField === "all" ? QUESTIONS : QUESTIONS.filter(q => q.field === selectedField);
      setCurrentQ(pickQuestion(pool, newResults, sessionSeen));
      setPhase("question");
      setIsCorrect(null);
      autoTimer.current = null;
    }, delay);
  };

  const pred = calcPrediction(results);
  const dueCount = QUESTIONS.filter(q => isDue(results[q.id])).length;
  const weakList = getWeakTop5(results);

  const s = {
    app: { background: C.bg, minHeight: "100vh", color: C.text, fontFamily: "'Hiragino Kaku Gothic Pro','Noto Sans JP',sans-serif", display: "flex", flexDirection: "column", maxWidth: 480, margin: "0 auto" },
    hdr: { background: C.bg2, padding: "10px 16px 8px", borderBottom: `1px solid ${C.border}`, position: "sticky", top: 0, zIndex: 50 },
    content: { flex: 1, overflowY: "auto", padding: 14, paddingBottom: 76 },
    card: { background: C.bg2, borderRadius: 12, padding: 14, marginBottom: 10, border: `1px solid ${C.border}` },
    tabBar: { position: "fixed", bottom: 0, left: "50%", transform: "translateX(-50%)", width: "100%", maxWidth: 480, background: C.bg2, borderTop: `1px solid ${C.border}`, display: "flex", zIndex: 100 },
    tab: active => ({ flex: 1, padding: "9px 2px 7px", textAlign: "center", fontSize: 11, color: active ? C.gold : C.sub, fontWeight: active ? 700 : 400, cursor: "pointer", background: "none", border: "none", borderTop: `2px solid ${active ? C.gold : "transparent"}` }),
    secTitle: { fontSize: 11, fontWeight: 700, color: C.gold, letterSpacing: 1, marginBottom: 10, textTransform: "uppercase" },
    statBar: { height: 6, borderRadius: 3, background: C.border, overflow: "hidden", marginBottom: 3 },
    fill: (pct, col) => ({ height: "100%", width: `${Math.min(100, pct)}%`, background: col, borderRadius: 3, transition: "width 0.6s" }),
    nextBtn: { width: "100%", padding: 13, borderRadius: 10, background: `linear-gradient(135deg,${C.gold},${C.gold2})`, border: "none", color: C.bg, fontSize: 15, fontWeight: 700, cursor: "pointer", marginTop: 8 },
  };

  const renderQuiz = () => (
    <div>
      <div style={{ display: "flex", gap: 6, marginBottom: 12, overflowX: "auto", paddingBottom: 2 }}>
        {["all", ...FIELDS].map(f => (
          <button key={f} onClick={() => setSelectedField(f)} style={{ whiteSpace: "nowrap", padding: "4px 10px", borderRadius: 20, border: `1px solid ${selectedField === f ? C.gold : C.border}`, background: selectedField === f ? `${C.gold}22` : "transparent", color: selectedField === f ? C.gold : C.sub, fontSize: 11, cursor: "pointer", fontWeight: selectedField === f ? 700 : 400 }}>
            {f === "all" ? "全分野" : f}
          </button>
        ))}
      </div>
      <div style={{ display: "flex", gap: 8, marginBottom: 12 }}>
        {[
          { val: sessionScore.total > 0 ? Math.round(sessionScore.correct / sessionScore.total * 100) + "%" : "--", label: "今回正答率", color: C.gold },
          { val: `🔥${streak}`, label: "連続正解", color: streak >= 5 ? "#ff9a3c" : C.text },
          { val: pred.mastered, label: "習得済み", color: C.green },
        ].map(({ val, label, color }) => (
          <div key={label} style={{ ...s.card, flex: 1, padding: "8px 4px", marginBottom: 0, textAlign: "center" }}>
            <div style={{ fontSize: 17, fontWeight: 700, color }}>{val}</div>
            <div style={{ fontSize: 9, color: C.sub }}>{label}</div>
          </div>
        ))}
      </div>
      {currentQ && phase === "question" && (
        <>
          <div style={s.card}>
            <div style={{ fontSize: 10, color: C.gold, fontWeight: 700, letterSpacing: 1, marginBottom: 6 }}>{currentQ.field} ▸ {currentQ.tag}</div>
            <div style={{ fontSize: 15, lineHeight: 1.75, fontWeight: 400, color: "#4a7a4a" }}>{currentQ.q}</div>
          </div>
          {currentQ.choices.length === 2 ? (
            <div style={{ display: "flex", gap: 10, padding: "2px 0" }}>
              {[["🌸","○","#d4888f"],["💩","×","#a08060"]].map(([emoji,val,col]) => (
                <button key={val} onClick={() => handleAnswer(val)} style={{ flex: 1, padding: 18, borderRadius: 12, border: `1px solid ${col}`, background: "transparent", color: col, fontSize: 28, fontWeight: 400, cursor: "pointer" }}>{emoji}</button>
              ))}
            </div>
          ) : (
            <div style={s.card}>
              {currentQ.choices.map(c => (
                <button key={c} onClick={() => handleAnswer(c)} style={{ width: "100%", padding: "11px 12px", marginBottom: 7, borderRadius: 9, border: `1px solid ${C.border}`, background: `${C.blue}22`, color: C.muted, fontSize: 13, fontWeight: 500, cursor: "pointer", textAlign: "left" }}>{c}</button>
              ))}
            </div>
          )}
        </>
      )}
      {currentQ && phase === "feedback" && (
        <div>
          <div style={{ ...s.card, borderLeft: `4px solid ${isCorrect ? C.green : C.red}` }}>
            <div style={{ fontSize: 13, fontWeight: 700, color: isCorrect ? C.green : C.red, marginBottom: 10 }}>{isCorrect ? "○ 正解" : "× 不正解"}</div>
            <div style={{ fontSize: 15, lineHeight: 1.9, color: "#c0406a", fontWeight: 400, marginBottom: 14 }}>{isCorrect ? currentQ.fb_ok : currentQ.fb_ng}</div>
            <div style={{ display: "flex", gap: 8 }}>
              <button onClick={() => { if (autoTimer.current) { clearTimeout(autoTimer.current); autoTimer.current = null; } setStopped(true); }}
                style={{ flex: 1, padding: 11, borderRadius: 9, border: "1px solid #a8b8e8", background: stopped ? "#c8d4e8" : "transparent", color: stopped ? "#4a5a8a" : "#c47a8a", fontSize: 13, cursor: "pointer", fontWeight: 500 }}>
                {stopped ? "⏸ 停止中" : "⏸ 停止"}
              </button>
              <button onClick={() => { if (autoTimer.current) clearTimeout(autoTimer.current); const pool = selectedField === "all" ? QUESTIONS : QUESTIONS.filter(q => q.field === selectedField); setCurrentQ(pickQuestion(pool, results, sessionSeen)); setPhase("question"); setIsCorrect(null); setStopped(false); }}
                style={{ flex: 2, padding: 11, borderRadius: 9, border: "1px solid #c8925c", background: "#e5c9a8", color: "#6e3a1a", fontSize: 13, cursor: "pointer", fontWeight: 500 }}>
                次の問題へ →
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );

  const renderStats = () => {
    const fieldStats = FIELDS.map(f => {
      const acc = calcFieldAccSingle(f, results);
      const qs = QUESTIONS.filter(q => q.field === f);
      const mastered = qs.filter(q => isMastered(results[q.id], QUESTIONS.length)).length;
      return { f, acc, mastered, total: qs.length };
    });
    return (
      <div>
        <div style={s.card}>
          <div style={s.secTitle}>総合進捗</div>
          <div style={{ fontSize: 10, color: C.sub, marginBottom: 8 }}>※ 同じ問題に7回正解で「習得済み」になるちゃむ</div>
          <div style={{ textAlign: "center", padding: "8px 0 12px" }}>
            <div style={{ fontSize: 44, fontWeight: 700, color: C.gold, lineHeight: 1 }}>{pred.pct}<span style={{ fontSize: 20 }}>%</span></div>
            <div style={{ fontSize: 13, color: C.sub, marginTop: 4 }}>{pred.label} — 習得 {pred.mastered}/{pred.total}</div>
          </div>
          <div style={s.statBar}><div style={s.fill(pred.pct, `linear-gradient(90deg,${C.gold},${C.gold2})`)} /></div>
        </div>
        <div style={s.card}>
          <div style={s.secTitle}>分野別正解率</div>
          {fieldStats.map(({ f, acc, mastered, total }) => (
            <div key={f} style={{ marginBottom: 10 }}>
              <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 3 }}>
                <span style={{ fontSize: 12, color: C.muted }}>{f}</span>
                <span style={{ fontSize: 10, color: C.sub }}>{mastered}/{total} | {acc !== null ? Math.round(acc * 100) : "--"}%</span>
              </div>
              <div style={s.statBar}><div style={s.fill(acc !== null ? acc * 100 : 0, acc !== null ? acc >= 0.7 ? C.green : acc >= 0.5 ? C.gold : C.red : C.border)} /></div>
            </div>
          ))}
        </div>

        <button onClick={() => { if (window.confirm("学習データをリセットしますか？")) { save("results", {}); setResults({}); setSessionScore({ correct: 0, total: 0 }); setStreak(0); } }} style={{ width: "100%", padding: 12, borderRadius: 10, background: "transparent", border: `1px solid ${C.red}`, color: C.red, fontSize: 13, cursor: "pointer" }}>
          データをリセット
        </button>
      </div>
    );
  };

  const renderWeak = () => (
    <div>
      <div style={s.card}>
        <div style={s.secTitle}>🔴 弱点問題 TOP5</div>
        {weakList.length === 0 ? (
          <div style={{ textAlign: "center", color: C.sub, padding: "20px 0" }}>問題を解いて弱点を見つけてちゃむ🌸</div>
        ) : weakList.map(({ q, acc, count }) => (
          <div key={q.id} style={{ borderBottom: `1px solid ${C.border}`, paddingBottom: 12, marginBottom: 12 }}>
            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
              <span style={{ fontSize: 10, color: C.gold }}>{q.field}</span>
              <span style={{ fontSize: 10, color: acc < 0.5 ? C.red : C.gold }}>{Math.round(acc * 100)}% ({count}回)</span>
            </div>
            <div style={{ fontSize: 13, color: C.muted, lineHeight: 1.6, marginBottom: 8 }}>{q.q.length > 50 ? q.q.slice(0, 50) + "…" : q.q}</div>
            <button onClick={() => { setCurrentQ(q); setPhase("question"); setTab("quiz"); }} style={{ padding: "4px 10px", borderRadius: 6, background: `${C.gold}22`, border: `1px solid ${C.gold}`, color: C.gold, fontSize: 11, cursor: "pointer" }}>この問題を解く</button>
          </div>
        ))}
      </div>
      <div style={s.card}>
        <div style={s.secTitle}>未学習問題</div>
        <div style={{ fontSize: 22, fontWeight: 700, color: C.blue, textAlign: "center" }}>
          {QUESTIONS.filter(q => !results[q.id]?.history?.length).length}<span style={{ fontSize: 13, color: C.sub, marginLeft: 4 }}>問</span>
        </div>
        <div style={{ fontSize: 11, color: C.sub, textAlign: "center", marginTop: 4 }}>アルゴリズムが自動で優先出題するちゃむ🌸</div>
      </div>
    </div>
  );

  const renderReview = () => {
    const dueList = QUESTIONS.filter(q => isDue(results[q.id]));
    return (
      <div>
        <div style={s.card}>
          <div style={s.secTitle}>🔔 本日の復習</div>
          {dueList.length === 0 ? (
            <div style={{ textAlign: "center", color: C.green, padding: "16px 0" }}>
              <div style={{ fontSize: 22, marginBottom: 6 }}>✓</div>
              <div style={{ fontSize: 13 }}>今日の復習は完了ちゃむ🌸</div>
            </div>
          ) : (
            <>
              <div style={{ fontSize: 13, color: C.gold, marginBottom: 10 }}>{dueList.length}問 復習待ちちゃむ</div>
              {dueList.slice(0, 5).map(q => (
                <div key={q.id} style={{ borderBottom: `1px solid ${C.border}`, paddingBottom: 10, marginBottom: 10 }}>
                  <div style={{ fontSize: 10, color: C.sub, marginBottom: 3 }}>{q.field} ▸ {q.tag}</div>
                  <div style={{ fontSize: 13, color: C.muted, lineHeight: 1.5, marginBottom: 6 }}>{q.q.length > 45 ? q.q.slice(0, 45) + "…" : q.q}</div>
                  <button onClick={() => { setCurrentQ(q); setPhase("question"); setTab("quiz"); }} style={{ padding: "4px 10px", borderRadius: 6, background: `${C.green}22`, border: `1px solid ${C.green}`, color: C.green, fontSize: 11, cursor: "pointer" }}>復習する</button>
                </div>
              ))}
              {dueList.length > 5 && <div style={{ fontSize: 11, color: C.sub, textAlign: "center" }}>他 {dueList.length - 5}問</div>}
            </>
          )}
        </div>
        <div style={s.card}>
          <div style={s.secTitle}>習得進捗</div>
          <div style={{ textAlign: "center" }}>
            <div style={{ fontSize: 34, fontWeight: 700, color: C.green }}>{pred.mastered}<span style={{ fontSize: 14, color: C.sub }}>/{pred.total}</span></div>
            <div style={{ fontSize: 12, color: C.sub }}>{pred.label}</div>
          </div>
          <div style={{ ...s.statBar, marginTop: 10 }}><div style={s.fill(pred.pct, C.green)} /></div>
        </div>
      </div>
    );
  };

  return (
    <div style={s.app}>
      <div style={s.hdr}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
          <div>
            <div style={{ fontSize: 13, fontWeight: 700, color: C.gold, letterSpacing: 2 }}>📖 日常民法道場</div>
            <div style={{ fontSize: 10, color: C.sub }}>日常×民法 {QUESTIONS.length}問 | {pred.mastered}問習得</div>
          </div>
          {dueCount > 0 && <div style={{ background: `${C.red}33`, color: C.red, border: `1px solid ${C.red}`, borderRadius: 20, padding: "2px 8px", fontSize: 11, fontWeight: 700 }}>🔔{dueCount}</div>}
        </div>
        <div>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 4 }}>
            <span style={{ fontSize: 12, color: C.text, fontWeight: 600 }}>今日 {todayCount}問 / 目標 <span style={{color:"#ff7c2a"}}>累計{totalSolved}問</span></span>
            <select value={goal} onChange={e => { const g = Number(e.target.value); setGoal(g); setTodayCount(0); save("todayCount", 0); save("goal", g); }}
              style={{ fontSize: 11, color: C.gold, background: "transparent", border: `1px solid ${C.border}`, borderRadius: 6, padding: "1px 4px", cursor: "pointer" }}>
              {[10,20,30,50,100,150,200].map(n => <option key={n} value={n}>{n}問</option>)}
            </select>
          </div>
          <div style={{ background: "#ede8e0", height: 6, borderRadius: 3, overflow: "hidden" }}>
            <div style={{ width: `${Math.min(100, todayCount / goal * 100)}%`, background: todayCount >= goal ? C.green : "#ff7c2a", height: 6, borderRadius: 3, transition: "width 0.4s" }} />
          </div>
          {todayCount >= goal && <div style={{ fontSize: 10, color: C.green, textAlign: "right", marginTop: 2 }}>🎉 目標達成！</div>}
          <div style={{ display: "flex", gap: 10, marginTop: 4 }}>
            <span style={{ fontSize: 10, color: C.green }}>✓ 正解 {sessionScore.correct}</span>
            <span style={{ fontSize: 10, color: C.red }}>✗ 不正解 {sessionScore.total - sessionScore.correct}</span>
            <span style={{ fontSize: 10, color: C.sub }}>計 {sessionScore.total}問</span>
          </div>
        </div>
      </div>
      <div style={{ ...s.content, transition: "background 0.3s", background: flash === "ok" ? "#c8f0e0" : flash === "ng" ? "#f5c8d0" : C.bg }}>
        {tab === "quiz" && renderQuiz()}
        {tab === "stats" && renderStats()}
        {tab === "weak" && renderWeak()}
        {tab === "review" && renderReview()}
      </div>
      <div style={s.tabBar}>
        {[["quiz","📝 問題"],["stats","📊 成績"],["weak","🔴 弱点"],["review","🔔 復習"]].map(([id,label]) => (
          <button key={id} style={s.tab(tab === id)} onClick={() => setTab(id)}>{label}</button>
        ))}
      </div>
    </div>
  );
}
